// FY27 prospect pipeline schema, fetcher, and verification gate.
// Source of truth: SharePoint file
// "FY27 DC CAP Revenue Planning Tool May 2026.xlsx" in
// /sites/Development/.../Budget/FY27/
//
// Each row carries a `_source` block so any value can be traced back to a
// specific tab + row in the source file. The verification gate refuses to
// publish pipeline.json if any row fails source-tagging or per-segment
// cross-foot checks.

export type Segment = 'Foundation' | 'Corporate' | 'Individual';
export type TierLevel = 1 | 2 | 3 | 4;

export interface PipelineRow {
  /** Stable id for React keys + edit tracking. */
  id: string;
  /** Funder display name. Free text on the source file. */
  funder: string;
  /** Foundation / Corporate / Individual — drives segment rollups. */
  segment: Segment;
  /** Confidence tier — 1 (Very Likely) to 4 (Not likely, pursuing for cultivation). */
  tier: TierLevel;
  /** Annual Operating Revenue ask in dollars. Drives Floor / Base / Stretch. */
  aorAmount: number;
  /** Optional restricted add-on (e.g., Carnegie $100K ask = $50K AOR + $50K restricted). Display only. */
  restrictedAddOn: number;
  /** DC CAP Constituent ID from source file. Empty string if not yet assigned. */
  constituentId: string;
  /** Gift-officer / portfolio attribution. Auto-populated from Individual tab "Portfolio Assignment". */
  owner: string;
  /** Free-text notes from the source file. */
  notes: string;
  /** Provenance block — every row must trace to a specific source tab + row. */
  _source: {
    tab: Segment;
    rowIndex: number; // 1-indexed row number in the source tab
  };
}

export interface SegmentBaseline {
  /** Pre-Booked AOR per segment per fiscal year — the locked operational baseline that sits underneath Floor. */
  fy27: number;
  fy28: number;
  fy29: number;
}

export interface SegmentGoal {
  /** Goals from the file's summary tab — what the team is committing to raise. */
  fy27NewAor: number;
  fy28NewAor: number;
  fy29NewAor: number;
}

/** Org-level FY27 / FY28 / FY29 triple from the Summary tab. */
export interface OrgFiscalYear {
  /** "FY27 Annual Operating Revenue Goal" — the total revenue target including pre-booked. */
  totalAorGoal: number;
  /** "Pre-Booked AOR" — committed before the FY starts. */
  preBookedAor: number;
  /** "New AOR" — gap to close during the FY = totalAorGoal − preBookedAor. */
  newAorGoal: number;
}

/** Aggregate goals from the Event Break Out tab (separate from segment Non-Event pipeline). */
export interface EventGoals {
  totalGoal: number;
  tier1And2Goal: number;
  tier3And4Goal: number;
  byCategory: Record<Segment, number>;
}

export interface PipelineMeta {
  /** Source SharePoint URL — clickable from the tool. */
  sourceUrl: string;
  /** SharePoint lastModifiedDateTime — what we synced from. */
  fileLastModified: string; // ISO 8601
  /** When this pipeline.json was produced. */
  syncedAt: string; // ISO 8601
  /** Schema version — bump on breaking schema changes. */
  schemaVersion: 1;
  /** Per-tab row count parsed. */
  rowCounts: Record<Segment, number>;
  /** Whether the verification gate passed. Always true in published pipeline.json (else file is not published). */
  verified: boolean;
  /** Human-readable note from the verification step (passes / advisory / failures noted before publish). */
  verificationNote: string;
  /** Org-level FY27 triple from Summary tab R23-R25. Drives "% of $5.82M target" framing. */
  orgFy27?: OrgFiscalYear;
  /** Org-level FY28 + FY29 outyear triples for the multi-year glance. */
  orgOutyears?: { fy28: OrgFiscalYear; fy29: OrgFiscalYear };
  /** Per-segment Pre-Booked AOR as published on segment-tab R8. Mirrors baselines.fy27 but kept in meta so verification details survive future schema work. */
  preBookedBySegment?: Record<Segment, number>;
  /** Per-segment New-AOR goal as published on segment-tab R9. Often disagrees with the Summary tab — surfaced as a verification advisory. */
  segmentTabNewAor?: Record<Segment, number>;
  /** Aggregates from the Event Break Out tab. Null if the workbook predates the Event tab. */
  eventGoals?: EventGoals | null;
  /** Count of segment-tab rows flagged with the "EVENT?" column (cross-references the Event tab). */
  eventFlaggedCounts?: Record<Segment, number>;
}

export interface Pipeline {
  meta: PipelineMeta;
  rows: PipelineRow[];
  /** Per-segment Pre-Booked AOR baselines. Editable in the tool but seeded from file. */
  baselines: Record<Segment, SegmentBaseline>;
  /** Per-segment goals from the file's summary tab. */
  goals: Record<Segment, SegmentGoal>;
}

