// --- Fetch + cache ---

const STORAGE_KEY = 'tier-forecast-pipeline-v1';

/**
 * Fetch the published pipeline.json. Falls back to localStorage cache on
 * network failure, then to EMPTY_PIPELINE if no cache exists.
 */
export async function fetchPipeline(): Promise<Pipeline> {
  try {
    // Cache-bust on each load so a fresh deploy is picked up immediately.
    const res = await fetch(`./pipeline.json?t=${Date.now()}`, { cache: 'no-store' });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = (await res.json()) as Pipeline;
    if (data.meta?.schemaVersion !== 1) throw new Error('Schema mismatch');
    if (typeof window !== 'undefined') {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    }
    return data;
  } catch {
    if (typeof window !== 'undefined') {
      const cached = localStorage.getItem(STORAGE_KEY);
      if (cached) {
        try {
          return JSON.parse(cached) as Pipeline;
        } catch {
          /* fall through */
        }
      }
    }
    return EMPTY_PIPELINE;
  }
}

// --- Aggregations ---

export interface SegmentScenarios {
  /** Tier 1 AOR + Pre-Booked AOR baseline. */
  floor: number;
  /** Floor + Tier 2 AOR. */
  base: number;
  /** Base + Tier 3 AOR. */
  stretch: number;
  /** Tier 4 AOR — outside all three scenarios, upside only. */
  upside: number;
  /** Per-tier raw AOR sums for display. */
  tier1: number;
  tier2: number;
  tier3: number;
  tier4: number;
  /** Pre-Booked AOR baseline added to Floor. */
  preBookedAor: number;
  /** Per-tier prospect counts. */
  tier1Count: number;
  tier2Count: number;
  tier3Count: number;
  tier4Count: number;
  /** Sized = aorAmount > 0. Unsized = aorAmount === 0 (cultivation prospect, ask TBD). */
  sizedCount: number;
  unsizedCount: number;
}

export function aggregateSegment(
  rows: PipelineRow[],
  segment: Segment,
  baseline: number
): SegmentScenarios {
  const segRows = rows.filter((r) => r.segment === segment);
  const byTier = (t: TierLevel) => segRows.filter((r) => r.tier === t);
  const sumAor = (rs: PipelineRow[]) => rs.reduce((s, r) => s + r.aorAmount, 0);
  const tier1Rows = byTier(1);
  const tier2Rows = byTier(2);
  const tier3Rows = byTier(3);
  const tier4Rows = byTier(4);
  const tier1 = sumAor(tier1Rows);
  const tier2 = sumAor(tier2Rows);
  const tier3 = sumAor(tier3Rows);
  const tier4 = sumAor(tier4Rows);
  const floor = baseline + tier1;
  const base = floor + tier2;
  const stretch = base + tier3;
  const sizedCount = segRows.filter((r) => r.aorAmount > 0).length;
  const unsizedCount = segRows.length - sizedCount;
  return {
    floor,
    base,
    stretch,
    upside: tier4,
    tier1,
    tier2,
    tier3,
    tier4,
    preBookedAor: baseline,
    tier1Count: tier1Rows.length,
    tier2Count: tier2Rows.length,
    tier3Count: tier3Rows.length,
    tier4Count: tier4Rows.length,
    sizedCount,
    unsizedCount,
  };
}

/**
 * Close-rate matrix for the Sensitivity overlay. 1.0 = full credit (cutoff method
 * default). The Sensitivity feature lets the IC ask "what if Tier 1 drifts 80% /
 * Tier 2 drifts 50%?" without altering the canonical Floor/Base/Stretch math.
 */
export type CloseRateMatrix = Record<Segment, Record<TierLevel, number>>;

export const CUTOFF_RATES_FLOOR: CloseRateMatrix = {
  Foundation: { 1: 1, 2: 0, 3: 0, 4: 0 },
  Corporate: { 1: 1, 2: 0, 3: 0, 4: 0 },
  Individual: { 1: 1, 2: 0, 3: 0, 4: 0 },
};
export const CUTOFF_RATES_BASE: CloseRateMatrix = {
  Foundation: { 1: 1, 2: 1, 3: 0, 4: 0 },
  Corporate: { 1: 1, 2: 1, 3: 0, 4: 0 },
  Individual: { 1: 1, 2: 1, 3: 0, 4: 0 },
};
export const CUTOFF_RATES_STRETCH: CloseRateMatrix = {
  Foundation: { 1: 1, 2: 1, 3: 1, 4: 0 },
  Corporate: { 1: 1, 2: 1, 3: 1, 4: 0 },
  Individual: { 1: 1, 2: 1, 3: 1, 4: 0 },
};

/** Sensitivity preset: same rates across all segments. */
const uniform = (r1: number, r2: number, r3: number): CloseRateMatrix => ({
  Foundation: { 1: r1, 2: r2, 3: r3, 4: 0 },
  Corporate: { 1: r1, 2: r2, 3: r3, 4: 0 },
  Individual: { 1: r1, 2: r2, 3: r3, 4: 0 },
});

export interface SensitivityPreset {
  key: string;
  label: string;
  hint: string;
  rates: CloseRateMatrix;
}

/**
 * NFF benchmark rates approximate Nonprofit Finance Fund / sector-survey close rates
 * for tiered prospect pipelines. Treat as illustrative, not actuarial — DC CAP has
 * no historical close-rate ground truth (deliberate, see ROADMAP non-goals).
 */
