/**
 * Per-segment weighted Floor / Base / Stretch under a single close-rate matrix.
 * Mirrors the cutoff method's tier-inclusion structure but with fractional
 * close rates instead of 100%/0%:
 *   Weighted Floor   = Pre-Booked + rate[T1] × T1
 *   Weighted Base    = Floor + rate[T2] × T2
 *   Weighted Stretch = Base + rate[T3] × T3
 * Tier 4 always zero by construction (outside scenarios).
 */
export interface WeightedSegmentTriple {
  floor: number;
  base: number;
  stretch: number;
}

export interface WeightedScenarioTriple {
  floor: number;
  base: number;
  stretch: number;
  perSegment: Record<Segment, WeightedSegmentTriple>;
}

/**
 * Apply a close-rate matrix to produce weighted Floor / Base / Stretch totals
 * per segment + combined. The IC's "what if T1 drops 20%?" question is best
 * answered against this triple, not a single weighted number.
 */
export function aggregateWeighted(
  rows: PipelineRow[],
  baselines: Record<Segment, SegmentBaseline>,
  rates: CloseRateMatrix
): WeightedScenarioTriple {
  const segTriple = (seg: Segment): WeightedSegmentTriple => {
    const baseline = baselines[seg].fy27;
    const tierSum = (t: TierLevel) =>
      rows
        .filter((r) => r.segment === seg && r.tier === t)
        .reduce((sum, r) => sum + r.aorAmount * rates[seg][t], 0);
    const t1 = tierSum(1);
    const t2 = tierSum(2);
    const t3 = tierSum(3);
    const floor = baseline + t1;
    const base = floor + t2;
    const stretch = base + t3;
    return { floor, base, stretch };
  };
  const F = segTriple('Foundation');
  const C = segTriple('Corporate');
  const I = segTriple('Individual');
  return {
    floor: F.floor + C.floor + I.floor,
    base: F.base + C.base + I.base,
    stretch: F.stretch + C.stretch + I.stretch,
    perSegment: { Foundation: F, Corporate: C, Individual: I },
  };
}

/** Combined Floor / Base / Stretch across all three segments. */
export function aggregateCombined(
  rows: PipelineRow[],
  baselines: Record<Segment, SegmentBaseline>
): SegmentScenarios {
  const f = aggregateSegment(rows, 'Foundation', baselines.Foundation.fy27);
  const c = aggregateSegment(rows, 'Corporate', baselines.Corporate.fy27);
  const i = aggregateSegment(rows, 'Individual', baselines.Individual.fy27);
  return {
    floor: f.floor + c.floor + i.floor,
    base: f.base + c.base + i.base,
    stretch: f.stretch + c.stretch + i.stretch,
    upside: f.upside + c.upside + i.upside,
    tier1: f.tier1 + c.tier1 + i.tier1,
    tier2: f.tier2 + c.tier2 + i.tier2,
    tier3: f.tier3 + c.tier3 + i.tier3,
    tier4: f.tier4 + c.tier4 + i.tier4,
    preBookedAor: f.preBookedAor + c.preBookedAor + i.preBookedAor,
    tier1Count: f.tier1Count + c.tier1Count + i.tier1Count,
    tier2Count: f.tier2Count + c.tier2Count + i.tier2Count,
    tier3Count: f.tier3Count + c.tier3Count + i.tier3Count,
    tier4Count: f.tier4Count + c.tier4Count + i.tier4Count,
    sizedCount: f.sizedCount + c.sizedCount + i.sizedCount,
    unsizedCount: f.unsizedCount + c.unsizedCount + i.unsizedCount,
  };
}

// --- Verification gate ---
// Run before any deploy. If any check fails, the pipeline.json must NOT be
// published. Each refresh (manual or scheduled) routes through this gate.

export interface VerificationResult {
  passed: boolean;
  checks: {
    name: string;
    passed: boolean;
    detail: string;
  }[];
}

export interface VerificationInput {
  pipeline: Pipeline;
  /** Per-tab counts published in the source file — for cross-foot validation. */
  fileCounts?: Record<Segment, number>;
  /** Per-tier AOR totals published in the source file (advisory until structured Excel parse). */
  fileTierTotals?: Partial<Record<Segment, Partial<Record<TierLevel, number>>>>;
}

export function runVerificationGate(input: VerificationInput): VerificationResult {
  const { pipeline, fileCounts, fileTierTotals } = input;
  const checks: VerificationResult['checks'] = [];

  // Check 1: meta block populated
  checks.push({
    name: 'meta.fileLastModified populated',
    passed: !!pipeline.meta.fileLastModified,
    detail: pipeline.meta.fileLastModified || 'EMPTY',
  });

  // Check 2: all three segments present with rows
  const segs: Segment[] = ['Foundation', 'Corporate', 'Individual'];
  for (const seg of segs) {
    const segRows = pipeline.rows.filter((r) => r.segment === seg);
    checks.push({
      name: `${seg} has rows`,
      passed: segRows.length > 0,
      detail: `${segRows.length} rows`,
    });
  }

  // Check 3: every row has required fields + valid _source
  const invalidRows = pipeline.rows.filter(
    (r) =>
      !r.funder ||
      ![1, 2, 3, 4].includes(r.tier) ||
      !Number.isFinite(r.aorAmount) ||
      r.aorAmount < 0 ||
      !r._source ||
      !segs.includes(r._source.tab) ||
      !Number.isInteger(r._source.rowIndex) ||
      r._source.rowIndex < 1
  );
  checks.push({
    name: 'all rows have valid fields + _source',
    passed: invalidRows.length === 0,
    detail:
      invalidRows.length === 0
        ? `${pipeline.rows.length} rows validated`
        : `${invalidRows.length} invalid: ${invalidRows
            .slice(0, 3)
            .map((r) => r.funder || '(blank)')
            .join(', ')}`,
  });

  // Check 4: row counts match file (if provided)
  if (fileCounts) {
    for (const seg of segs) {
      const parsed = pipeline.rows.filter((r) => r.segment === seg).length;
      const expected = fileCounts[seg];
      checks.push({
        name: `${seg} row count matches file`,
        passed: parsed === expected,
        detail: `parsed ${parsed} · file ${expected}`,
      });
    }
  }

  // Check 5: per-tier AOR cross-foot vs file's published totals (if provided)
  if (fileTierTotals) {
    for (const seg of segs) {
      const segTotals = fileTierTotals[seg];
      if (!segTotals) continue;
      for (const tier of [1, 2, 3, 4] as TierLevel[]) {
        const expected = segTotals[tier];
        if (expected === undefined) continue;
        const parsed = pipeline.rows
          .filter((r) => r.segment === seg && r.tier === tier)
          .reduce((s, r) => s + r.aorAmount, 0);
        const delta = Math.abs(parsed - expected);
        checks.push({
          name: `${seg} Tier ${tier} cross-foot`,
          passed: delta <= 1, // $1 tolerance for rounding
          detail: `parsed $${parsed.toLocaleString()} · file $${expected.toLocaleString()} · Δ $${delta.toLocaleString()}`,
        });
      }
    }
  }

  return {
    passed: checks.every((c) => c.passed),
    checks,
  };
}
