import { useState } from 'react';
import type { FinancialInputs, ScenarioName } from '../lib/model';
import {
  DEFAULT_INPUTS,
  DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE,
  fiscalYears,
  isDevOfficeAspirationActive,
} from '../lib/model';
import { fyLabel } from '../lib/format';

interface InputsPanelProps {
  inputs: FinancialInputs;
  setInputs: (next: FinancialInputs) => void;
}

type SubTab = 'financial' | 'market' | 'endowment';

export function InputsPanel({ inputs, setInputs }: InputsPanelProps) {
  const [tab, setTab] = useState<SubTab>('financial');
  const years = fiscalYears();

  const updateArr = (
    key: 'awardCosts' | 'fundraising' | 'additionsToEndowment',
    idx: number,
    valueDollars: number
  ) => {
    const next = [...inputs[key]];
    next[idx] = valueDollars;
    setInputs({ ...inputs, [key]: next });
  };

  const updatePriorBalance = (idx: number, valueDollars: number) => {
    const next = [...inputs.priorYearBalances];
    next[idx] = valueDollars;
    setInputs({ ...inputs, priorYearBalances: next });
  };

  const updateMarket = (scenario: ScenarioName, idx: number, valuePct: number) => {
    const arr = [...inputs.marketReturn[scenario]];
    arr[idx] = valuePct;
    setInputs({
      ...inputs,
      marketReturn: { ...inputs.marketReturn, [scenario]: arr },
    });
  };

  const isDirty = JSON.stringify(inputs) !== JSON.stringify(DEFAULT_INPUTS);

  return (
    <aside className="card sticky top-4">
      <div className="card-header flex items-center justify-between gap-2">
        <span className="font-head uppercase tracking-wide-15 text-sm">Forecast Parameters</span>
        <button
          type="button"
          onClick={() => setInputs(DEFAULT_INPUTS)}
          disabled={!isDirty}
          title={
            isDirty
              ? 'Restore all inputs (financial, market, endowment) to the DRAFT FY27 budget defaults (pending Board approval)'
              : 'Inputs already match the DRAFT FY27 budget defaults'
          }
          className={`text-[10px] uppercase tracking-wide-15 font-head px-2 py-1 rounded border transition-colors ${
            isDirty
              ? 'border-purple/40 text-purple-deep hover:bg-purple/10 cursor-pointer'
              : 'border-navy/10 text-navy/30 cursor-not-allowed'
          }`}
        >
          Restore defaults
        </button>
      </div>
      <div className="px-3 pt-3">
        <div className="flex gap-1 bg-tan rounded-lg p-1">
          <button
            className={`tab-btn flex-1 ${tab === 'financial' ? 'tab-btn-active' : ''}`}
            onClick={() => setTab('financial')}
          >
            Financial
          </button>
          <button
            className={`tab-btn flex-1 ${tab === 'market' ? 'tab-btn-active' : ''}`}
            onClick={() => setTab('market')}
          >
            Market
          </button>
          <button
            className={`tab-btn flex-1 ${tab === 'endowment' ? 'tab-btn-active' : ''}`}
            onClick={() => setTab('endowment')}
          >
            Endowment
          </button>
        </div>
      </div>

      <div className="card-body max-h-[calc(100vh-13rem)] overflow-y-auto">
        {tab === 'financial' && (
          <div className="space-y-5">
            <div>
              <div className="eyebrow mb-1">Endowment</div>
              <div className="input-row">
                <label className="label">FY27 beginning ($M)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={(inputs.beginningEndowment / 1_000_000).toFixed(1)}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      beginningEndowment: Number(e.target.value) * 1_000_000,
                    })
                  }
                />
              </div>
            </div>

            <div>
              <div className="eyebrow mb-1">Operating revenue by year ($M)</div>
              <p className="text-xs text-navy/55 mb-2 font-sub leading-snug">
                Gifts + grants + events + contributed services + AOR releases.
                The endowment draw is the residual that closes total expenses
                minus this number.
              </p>
              {(() => {
                const aspirationActive = isDevOfficeAspirationActive(
                  inputs.fundraising
                );
                return (
                  <div className="mb-3 rounded border border-purple/30 bg-purple/[0.04] p-2.5">
                    <div className="flex items-start gap-2">
                      <button
                        type="button"
                        onClick={() =>
                          setInputs({
                            ...inputs,
                            fundraising: [...DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE],
                          })
                        }
                        disabled={aspirationActive}
                        title={
                          aspirationActive
                            ? 'Dev Office aspirational plan is currently applied'
                            : 'Apply the Dev Office Pipeline Tool outyear aspiration: FY28 $6.25M, FY29 $6.35M, FY30+ $6.5M with 1%/yr drift. Use "Restore defaults" above to return to Finance-flat.'
                        }
                        className={`text-[10px] uppercase tracking-wide-15 font-head px-2 py-1 rounded border transition-colors whitespace-nowrap ${
                          aspirationActive
                            ? 'border-purple/30 text-purple-deep bg-purple/10 cursor-not-allowed'
                            : 'border-purple/40 text-purple-deep hover:bg-purple/10 cursor-pointer'
                        }`}
                      >
                        {aspirationActive
                          ? '✓ Dev Office plan active'
                          : 'Apply Dev Office aspirational plan'}
                      </button>
                    </div>
                    <p className="text-xs text-navy/65 mt-2 font-sub leading-snug">
                      Dev Office Pipeline aspiration — <strong>not in the
                      Finance DRAFT budget</strong>. Reconciled to Finance
                      through FY29 (matches Budget Preview's outyear panel),
                      then steps to $5.0M flat FY30+. Pipeline AOR commits
                      over a multi-year horizon; treat preset values as{' '}
                      <strong>upper bound on outyear P&amp;L recognition</strong>.
                      Actual P&amp;L typically lags AOR by ~$0.5M–$1M each
                      year as Pre-Booked rolls forward. FY27 stays at the
                      DRAFT-budget baseline ($4.70M).
                    </p>
                  </div>
                );
              })()}
              {years.map((fy, i) => (
                <div key={fy} className="input-row">
                  <label className="label">{fyLabel(fy)}</label>
                  <input
                    type="number"
                    step="0.1"
                    className="input-num"
                    value={(inputs.fundraising[i] / 1_000_000).toFixed(1)}
                    onChange={(e) =>
                      updateArr('fundraising', i, Number(e.target.value) * 1_000_000)
                    }
                  />
                </div>
              ))}
            </div>

            <div>
              <div className="eyebrow mb-1">Scholarship awards by year ($M)</div>
              {years.map((fy, i) => (
                <div key={fy} className="input-row">
                  <label className="label">{fyLabel(fy)}</label>
                  <input
                    type="number"
                    step="0.1"
                    className="input-num"
                    value={(inputs.awardCosts[i] / 1_000_000).toFixed(1)}
                    onChange={(e) =>
                      updateArr('awardCosts', i, Number(e.target.value) * 1_000_000)
                    }
                  />
                </div>
              ))}
            </div>

            <div>
              <div className="eyebrow mb-1">Operating expenses</div>
              <div className="input-row">
                <label className="label">FY27 init ($M)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={(inputs.opExpensesInit / 1_000_000).toFixed(1)}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      opExpensesInit: Number(e.target.value) * 1_000_000,
                    })
                  }
                />
              </div>
              <div className="input-row">
                <label className="label">Annual growth (%)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={inputs.opExpensesGrowth}
                  onChange={(e) =>
                    setInputs({ ...inputs, opExpensesGrowth: Number(e.target.value) })
                  }
                />
              </div>
              <div className="input-row">
                <label className="label">One-time reduction year</label>
                <input
                  type="number"
                  step="1"
                  className="input-num"
                  value={inputs.opExpensesReductionYear}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      opExpensesReductionYear: Number(e.target.value),
                    })
                  }
                />
              </div>
              <div className="input-row">
                <label className="label">Reduction amount ($M)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={(inputs.opExpensesReductionAmount / 1_000_000).toFixed(2)}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      opExpensesReductionAmount: Number(e.target.value) * 1_000_000,
                    })
                  }
                />
              </div>
            </div>
          </div>
        )}

        {tab === 'market' && (
          <div className="space-y-5">
            <p className="text-xs text-navy/70 font-sub leading-snug">
              DC CAP market-return assumptions — our forecast, not Finance policy.
              These drive the endowment balance, which drives next year's draw.
            </p>
            <p className="text-xs text-navy/55 font-sub leading-snug rounded border border-navy/10 bg-tan/40 px-2.5 py-2">
              <span className="font-semibold text-navy">Tool defaults:</span>{' '}
              6.5% Base · 8.0% Optimistic · −10% / −10% then recovery to 6.5%
              (Pessimistic). <em>IPS target to confirm with the Investment
              Committee</em> — these defaults are the modeling baseline, not the
              IPS itself.
            </p>
            {(['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) => (
              <div key={s}>
                <div className="eyebrow mb-1">{s} scenario — return %</div>
                {years.map((fy, i) => (
                  <div key={fy} className="input-row">
                    <label className="label">{fyLabel(fy)}</label>
                    <input
                      type="number"
                      step="0.1"
                      className="input-num"
                      value={inputs.marketReturn[s][i]}
                      onChange={(e) => updateMarket(s, i, Number(e.target.value))}
                    />
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}

        {tab === 'endowment' && (
          <div className="space-y-5">
            <p className="text-xs text-navy/70 font-sub leading-snug">
              The endowment draw is the residual — total expenses minus operating
              revenue — sized each year to balance the budget. The implied policy
              rate emerges as a diagnostic; it's not a knob.
            </p>

            <div>
              <div className="eyebrow mb-1">Restricted principal additions by year ($M)</div>
              <p className="text-xs text-navy/55 mb-2 font-sub leading-snug">
                Principal gifts directed to the endowment corpus — not operating
                revenue.
              </p>
              {years.map((fy, i) => (
                <div key={fy} className="input-row">
                  <label className="label">{fyLabel(fy)}</label>
                  <input
                    type="number"
                    step="0.1"
                    className="input-num"
                    value={(inputs.additionsToEndowment[i] / 1_000_000).toFixed(1)}
                    onChange={(e) =>
                      updateArr(
                        'additionsToEndowment',
                        i,
                        Number(e.target.value) * 1_000_000
                      )
                    }
                  />
                </div>
              ))}
            </div>

            <div>
              <div className="eyebrow mb-1">Prior-year ending balances ($M)</div>
              {(['FY24', 'FY25', 'FY26'] as const).map((label, i) => (
                <div key={label} className="input-row">
                  <label className="label">{label}</label>
                  <input
                    type="number"
                    step="0.1"
                    className="input-num"
                    value={((inputs.priorYearBalances[i] ?? 0) / 1_000_000).toFixed(1)}
                    onChange={(e) =>
                      updatePriorBalance(i, Number(e.target.value) * 1_000_000)
                    }
                  />
                </div>
              ))}
              <p className="text-xs text-navy/55 mt-1 font-sub leading-snug">
                Seeds the 3-yr rolling average — the denominator for the implied
                policy-rate diagnostic. FY24/FY25/FY26 endings feed FY27.
              </p>
            </div>
          </div>
        )}
      </div>
    </aside>
  );
}
