import { useRef, useState, type ReactNode } from 'react';
import { toPng } from 'html-to-image';

interface ExportButtonProps {
  /** The DOM element to capture as PNG. Must be a forwarded ref to a div/section. */
  targetRef: React.RefObject<HTMLElement | null>;
  /** Filename stem — date + ".png" / ".csv" appended automatically. */
  filename: string;
  /** Optional CSV export. When provided, a "Copy CSV" button appears alongside PNG. */
  csv?: {
    headers: string[];
    rows: (string | number)[][];
  };
  /** Optional label override; defaults to "Export". */
  label?: string;
  /** Pixel scale for the captured PNG. Default 2 = retina-grade. */
  pixelRatio?: number;
}

const today = () => new Date().toISOString().slice(0, 10);

function downloadBlob(content: string, mime: string, filename: string) {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function csvEscape(v: string | number): string {
  const s = String(v);
  if (s.includes(',') || s.includes('"') || s.includes('\n')) {
    return `"${s.replace(/"/g, '""')}"`;
  }
  return s;
}

function buildCsv(headers: string[], rows: (string | number)[][]): string {
  const lines = [headers.map(csvEscape).join(',')];
  for (const r of rows) {
    lines.push(r.map(csvEscape).join(','));
  }
  return lines.join('\n');
}

/**
 * ExportButton — captures a target DOM region as a high-resolution PNG (and
 * optionally as CSV) for board memos and one-pagers.
 *
 * PNG capture uses html-to-image with the target's bounding rect at 2× pixel
 * ratio (retina-grade). Background is forced to white so transparent charts
 * render correctly when pasted into Word / Pages / Google Docs.
 */
export function ExportButton({
  targetRef,
  filename,
  csv,
  label = 'Export',
  pixelRatio = 2,
}: ExportButtonProps) {
  const [status, setStatus] = useState<'idle' | 'capturing' | 'done' | 'error'>(
    'idle'
  );
  const timerRef = useRef<number | null>(null);

  const flashStatus = (next: 'done' | 'error') => {
    setStatus(next);
    if (timerRef.current) window.clearTimeout(timerRef.current);
    timerRef.current = window.setTimeout(() => setStatus('idle'), 1500);
  };

  const handlePng = async () => {
    if (!targetRef.current) {
      flashStatus('error');
      return;
    }
    setStatus('capturing');
    try {
      const dataUrl = await toPng(targetRef.current, {
        pixelRatio,
        backgroundColor: '#ffffff',
        cacheBust: true,
        // Skip web fonts mid-capture to avoid layout shift / blank glyphs.
        skipFonts: false,
      });
      const a = document.createElement('a');
      a.href = dataUrl;
      a.download = `${filename}-${today()}.png`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      flashStatus('done');
    } catch (e) {
      console.error('ExportButton PNG capture failed:', e);
      flashStatus('error');
    }
  };

  const handleCsv = () => {
    if (!csv) return;
    try {
      const content = buildCsv(csv.headers, csv.rows);
      downloadBlob(content, 'text/csv;charset=utf-8', `${filename}-${today()}.csv`);
      flashStatus('done');
    } catch (e) {
      console.error('ExportButton CSV failed:', e);
      flashStatus('error');
    }
  };

  const statusLabel: Record<typeof status, ReactNode> = {
    idle: null,
    capturing: <span className="text-navy/60">Capturing…</span>,
    done: <span className="text-emerald-700">Saved ✓</span>,
    error: <span className="text-rose-700">Failed</span>,
  };

  return (
    <div className="inline-flex items-center gap-2 text-xs no-print">
      <button
        type="button"
        onClick={handlePng}
        disabled={status === 'capturing'}
        className="px-2.5 py-1 rounded border border-navy/20 bg-white hover:bg-tan/40 text-navy/80 hover:text-navy font-head uppercase tracking-wide-15 transition-colors disabled:opacity-50"
        title={`Download high-resolution PNG (${pixelRatio}× pixel ratio)`}
      >
        {label} PNG
      </button>
      {csv && (
        <button
          type="button"
          onClick={handleCsv}
          className="px-2.5 py-1 rounded border border-navy/20 bg-white hover:bg-tan/40 text-navy/80 hover:text-navy font-head uppercase tracking-wide-15 transition-colors"
          title="Download data as CSV (for Excel / Sheets)"
        >
          {label} CSV
        </button>
      )}
      {statusLabel[status]}
    </div>
  );
}
