// historical.ts — schema, loader, and accessors for historical.json.
//
// Source: scripts/parse_historical.py reads
// `source_workbook/dccap_historic_financials_20250318.xlsx` — 13 years of
// FY12–FY24 actuals + FY25 projection (as of March 2025).
//
// The Historical Trends tab uses this to bookend the projection window: 13
// years of category-level history feeding into the FY26–FY35 forecast. Makes
// the projections defensible against "but is this realistic?" challenges.

export type LineCategory =
  | 'revenue'
  | 'revenue-total'
  | 'expense'
  | 'expense-total'
  | 'subtotal'
  | 'investment'
  | 'endowment'
  | 'balance'
  | 'balance-total';

export type FiscalYearKind = 'actual' | 'projection';

export interface FiscalYearMeta {
  fiscalYear: number;
  kind: FiscalYearKind;
}

export interface HistoricalSeries {
  key: string;
  label: string;
  category: LineCategory;
  row: number;
  /** Keyed by fiscalYear as string ("2012", "2013", ...). null = blank in source file. */
  values: Record<string, number | null>;
}

export interface HistoricalMeta {
  sourceFile: string;
  fileLastModified: string;
  syncedAt: string;
  schemaVersion: 1;
  earliestYear: number;
  latestYear: number;
  /** Most recent year the source file shows as actual (not projection). */
  actualThrough: number;
}

export interface Historical {
  meta: HistoricalMeta;
  fiscalYears: FiscalYearMeta[];
  series: Record<string, HistoricalSeries>;
}

// --- Loader ---

export async function fetchHistorical(): Promise<Historical> {
  const res = await fetch(`./historical.json?t=${Date.now()}`, { cache: 'no-store' });
  if (!res.ok) {
    throw new Error(`historical.json fetch failed: ${res.status} ${res.statusText}`);
  }
  return (await res.json()) as Historical;
}

// --- Accessors ---

/** Series keys grouped by their typical reporting section. Order matters for display. */
export const REVENUE_SERIES_KEYS = [
  'contributionsAndGrants',
  'governmentGrantRevenue',
  'specialEventsRevenue',
  'contributedServices',
  'releaseFromRestrictions',
] as const;

export const EXPENSE_SERIES_KEYS = [
  'salariesAndBenefits',
  'scholarshipAwards',
  'rentAndStorage',
  'otherExpenses',
  'depreciationAmortization',
] as const;

export const BALANCE_SERIES_KEYS = [
  'endowmentMarketValueHwRuane',
  'boaMarketValue',
  'totalInvestments',
] as const;

/** Returns the value for a (series, fy) pair, treating null/missing as 0. */
export function valueFor(h: Historical, seriesKey: string, fy: number): number {
  const s = h.series[seriesKey];
  if (!s) return 0;
  const v = s.values[String(fy)];
  return v ?? 0;
}

/** YoY % change for a series at fiscal year `fy` (vs fy − 1). Returns null when
 * the prior year is missing or zero. */
export function yoyChange(
  h: Historical,
  seriesKey: string,
  fy: number
): number | null {
  const cur = h.series[seriesKey]?.values[String(fy)];
  const prev = h.series[seriesKey]?.values[String(fy - 1)];
  if (cur == null || prev == null || prev === 0) return null;
  return (cur - prev) / prev;
}
