import { useCallback, useMemo, useRef, useState } from 'react';
import { ExportButton } from '../ExportButton';
import {
  CartesianGrid,
  Legend,
  Line,
  LineChart,
  ReferenceArea,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs, ScenarioName } from '../../lib/model';
import {
  FY27_AOR_RELEASES,
  FY27_NEW_CLOSES_BY_SEGMENT,
  FY27_NEW_CLOSES_TOTAL,
  FY27_OPERATING_REVENUE,
  HISTORICAL_ENDOWMENT,
  NACUBO_PEER_BANDS,
  RUNWAY_FLOOR_BALANCE,
  firstFloorCrossingYearIndex,
  projectAllScenarios,
  scenariosCrossingFloor,
} from '../../lib/model';
import { dollars, fyLabel, millions, percent } from '../../lib/format';
import { SCENARIO_COLORS } from '../../lib/colors';

// Compact millions formatter that strips trailing zeros after the decimal so
// $1,100,000 → "$1.1M" rather than "$1.10M", but $285,000 still shows as "$0.29M".
const fmtMillions = (n: number) =>
  `$${(n / 1_000_000).toFixed(2).replace(/\.?0+$/, '')}M`;

interface Props {
  inputs: FinancialInputs;
}

export function ScenarioOverview({ inputs }: Props) {
  const [scenario, setScenario] = useState<ScenarioName>('Base');
  const endowmentChartRef = useRef<HTMLElement>(null);
  const pAndLRef = useRef<HTMLElement>(null);
  const policyRateRef = useRef<HTMLElement>(null);

  const scenarios = useMemo(() => projectAllScenarios(inputs), [inputs]);
  const active = scenarios.find((s) => s.scenario === scenario)!;

  // Going-concern check: if any scenario crosses the runway floor in the first two
  // projection years, surface a board-attention banner above everything else.
  const firstCrossingIdx = useMemo(
    () => firstFloorCrossingYearIndex(scenarios, RUNWAY_FLOOR_BALANCE),
    [scenarios]
  );
  const crossingScenarios = useMemo(
    () =>
      firstCrossingIdx >= 0
        ? scenariosCrossingFloor(scenarios, RUNWAY_FLOOR_BALANCE, firstCrossingIdx)
        : [],
    [scenarios, firstCrossingIdx]
  );
  const goingConcernActive = firstCrossingIdx >= 0 && firstCrossingIdx < 2;

  // Policy-rate trajectory for NACUBO peer-band overlay (active scenario).
  const policyRateChartData = useMemo(
    () =>
      active.years.map((y) => ({
        fiscalYear: y.fiscalYear,
        policyRatePct: y.policyRate * 100,
      })),
    [active]
  );

  // Build chart data: historical + 3 scenarios
  const chartData = useMemo(() => {
    const map = new Map<number, Record<string, number | null>>();
    HISTORICAL_ENDOWMENT.forEach(({ fiscalYear, endingEndowment }) => {
      map.set(fiscalYear, { Historical: endingEndowment });
    });
    scenarios.forEach((s) => {
      s.years.forEach((y) => {
        const row = map.get(y.fiscalYear) ?? {};
        row[s.scenario] = y.endingEndowment;
        map.set(y.fiscalYear, row);
      });
    });
    // Bridge: include FY26 historical endpoint as the start of all scenario lines
    const lastHist = HISTORICAL_ENDOWMENT[HISTORICAL_ENDOWMENT.length - 1];
    const bridge = map.get(lastHist.fiscalYear) ?? {};
    bridge.Base = lastHist.endingEndowment;
    bridge.Optimistic = lastHist.endingEndowment;
    bridge.Pessimistic = lastHist.endingEndowment;
    map.set(lastHist.fiscalYear, bridge);

    return Array.from(map.entries())
      .sort(([a], [b]) => a - b)
      .map(([fiscalYear, vals]) => ({ fiscalYear, ...vals }));
  }, [scenarios]);

  // Derive the FY27 composition annotation from the budget-anchored constants. If the
  // user has edited operating revenue away from the budget value, suppress the
  // annotation rather than show stale segment numbers.
  const fy27UsesBudgetDefault =
    Math.abs((inputs.fundraising[0] ?? 0) - FY27_OPERATING_REVENUE) < 1;
  const seg = FY27_NEW_CLOSES_BY_SEGMENT;
  const fy27Composition = fy27UsesBudgetDefault
    ? `FY27 DRAFT budget*: ${fmtMillions(FY27_AOR_RELEASES)} recurring (releases from prior-year AOR) + ${fmtMillions(FY27_NEW_CLOSES_TOTAL)} new closes (Foundation ${fmtMillions(seg.foundation)} + Corp ${fmtMillions(seg.corporate)} + Indiv ${fmtMillions(seg.individual)} + Events ${fmtMillions(seg.events)} + in-kind ${fmtMillions(seg.inKind)}). This is Finance's commitment ledger view — see the FY27 Pipeline tab for Dev's prospect-level tracker, or the Revenue Detail tab for named-donor + gap-to-goal breakdown against the same target.`
    : null;

  const opPLRows = [
    {
      key: 'operatingRevenue',
      label: 'Operating revenue',
      sub: 'gifts + grants + events + contributed + AOR releases',
      fy27Composition,
    },
    {
      key: 'endowmentDraw',
      label: 'Endowment draw',
      sub: 'Residual — total expenses minus operating revenue',
    },
    { key: 'totalRevenue', label: 'Total revenue', emphasis: true },
    { key: 'awardCosts', label: 'Scholarship awards' },
    { key: 'opExpenses', label: 'Operating expenses' },
    { key: 'totalExpenses', label: 'Total expenses', emphasis: true },
    {
      key: 'operatingNetIncome',
      label: 'Operating surplus / (deficit)',
      emphasis: true,
      hint: 'Zero by construction — draw is sized to close this number every year.',
    },
  ] as const;

  const opPLMemoRows = [
    {
      label: 'Total donor dollars (operating + corpus)',
      hint: 'Operating revenue + restricted principal additions. Real money in the door from donors this year.',
      compute: (y: { operatingRevenue: number; additionsToEndowment: number }) =>
        y.operatingRevenue + y.additionsToEndowment,
    },
  ] as const;

  const endowmentActivityRows = [
    { key: 'beginningEndowment', label: 'Beginning balance', sign: 0 },
    { key: 'marketAppreciation', label: 'Market appreciation (scenario %)', sign: 1 },
    { key: 'endowmentDraw', label: 'Endowment draw', sign: -1 },
    { key: 'additionsToEndowment', label: 'Restricted principal additions', sign: 1 },
    { key: 'endingEndowment', label: 'Ending balance', emphasis: true, sign: 0 },
  ] as const;

  const memoRows = [
    {
      key: 'rollingAverageBalance',
      label: '3-yr rolling avg balance',
      format: 'dollars' as const,
      hint: 'Denominator for the policy-rate diagnostic.',
    },
    {
      key: 'policyRate',
      label: 'Policy rate (draw ÷ rolling avg)',
      format: 'percent' as const,
    },
    {
      key: 'actualRate',
      label: 'Actual rate (draw ÷ beginning balance)',
      format: 'percent' as const,
    },
  ] as const;

  const formatSigned = (value: number, sign: -1 | 0 | 1): string => {
    if (sign === 0 || value === 0) return dollars(value);
    const prefix = sign === 1 ? '+ ' : '− ';
    return prefix + dollars(Math.abs(value));
  };

  return (
    <div className="space-y-6">
      {goingConcernActive && (() => {
        const multiple = crossingScenarios.length > 1;
        const scenarioPhrase = `${crossingScenarios.join(' + ')} scenario${multiple ? 's' : ''}`;
        const verb = multiple ? 'cross' : 'crosses';
        const horizon = firstCrossingIdx === 0 ? '12 months' : '24 months';
        const crossingFy = fyLabel(active.years[firstCrossingIdx].fiscalYear);
        return (
          <section
            role="alert"
            className="rounded-md border-2 border-[#C8395B] bg-[#C8395B]/8 px-5 py-4"
          >
            <div className="flex items-start gap-3">
              <div className="text-[#C8395B] font-head font-bold uppercase text-xs tracking-wider mt-0.5">
                Board attention
              </div>
              <div className="flex-1 text-sm text-navy">
                <p className="font-semibold mb-1">
                  Floor crossing projected within {horizon} — {scenarioPhrase}{' '}
                  {verb} the {fmtMillions(RUNWAY_FLOOR_BALANCE)} runway floor by {crossingFy}.
                </p>
                <p className="text-xs text-navy/70 font-sub">
                  Strategic-timing threshold borrowed from the ASU 2014-15 substantial-doubt 12-month window — surfaced here as a board-attention heuristic, not as a compliance disclosure. Compliance reporting on going concern remains with the Finance team's audited statements.
                </p>
              </div>
            </div>
          </section>
        );
      })()}

      <HowToReadThisView />


      <section ref={endowmentChartRef} className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-2">
          <div>
            <div className="eyebrow">Endowment trajectory</div>
            <h2 className="font-head text-base">FY15 historical · FY27–FY35 projection</h2>
          </div>
          <ExportButton
            targetRef={endowmentChartRef}
            filename="endowment-trajectory"
            csv={{
              headers: ['Fiscal Year', 'Historical', 'Base', 'Optimistic', 'Pessimistic'],
              rows: chartData.map((d) => {
                const row = d as Record<string, number | null | undefined>;
                return [
                  d.fiscalYear,
                  row.Historical ?? '',
                  row.Base ?? '',
                  row.Optimistic ?? '',
                  row.Pessimistic ?? '',
                ];
              }) as (string | number)[][],
            }}
          />
        </div>
        <div className="card-body">
          <div
            className="h-[360px]"
            role="img"
            aria-label={(() => {
              const baseProj = scenarios.find((s) => s.scenario === 'Base')!;
              const optProj = scenarios.find((s) => s.scenario === 'Optimistic')!;
              const pessProj = scenarios.find((s) => s.scenario === 'Pessimistic')!;
              const baseLast = baseProj.years[baseProj.years.length - 1];
              const optLast = optProj.years[optProj.years.length - 1];
              const pessLast = pessProj.years[pessProj.years.length - 1];
              const fy15 = HISTORICAL_ENDOWMENT[0];
              const m = (n: number) => `$${(n / 1_000_000).toFixed(0)}M`;
              return `Endowment balance trajectory line chart. FY${String(
                fy15.fiscalYear
              ).slice(-2)} historical ${m(fy15.endingEndowment)} baseline, FY26 step-up to ${m(
                inputs.beginningEndowment
              )} after major-gift inflows, then projected through FY${String(
                baseLast.fiscalYear
              ).slice(-2)} under three scenarios. Base ends at ${m(
                baseLast.endingEndowment
              )}, Optimistic ${m(optLast.endingEndowment)}, Pessimistic ${m(
                pessLast.endingEndowment
              )}.`;
            })()}
          >
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C20" />
                <XAxis
                  dataKey="fiscalYear"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(fy) => fyLabel(Number(fy))}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  itemStyle={{ color: '#101A4C' }}
                  labelStyle={{ color: '#101A4C', fontWeight: 600 }}
                  formatter={(v) => millions(Number(v))}
                  labelFormatter={(fy) => `FY${String(fy).slice(-2)}`}
                />
                <Legend wrapperStyle={{ paddingTop: 8 }} />
                <Line
                  type="monotone"
                  dataKey="Historical"
                  stroke={SCENARIO_COLORS.Historical}
                  strokeWidth={2.5}
                  dot={false}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Base"
                  stroke={SCENARIO_COLORS.Base}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Optimistic"
                  stroke={SCENARIO_COLORS.Optimistic}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Pessimistic"
                  stroke={SCENARIO_COLORS.Pessimistic}
                  strokeWidth={2.5}
                  strokeDasharray="6 4"
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </section>

      <section ref={pAndLRef} className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-2">
          <div>
            <div className="eyebrow">Financial overview</div>
            <h2 className="font-head text-base">{scenario} scenario · FY27 – FY35</h2>
          </div>
          <div className="flex items-center gap-2 flex-wrap">
            <ExportButton
              targetRef={pAndLRef}
              filename={`operating-pnl-${scenario.toLowerCase()}`}
              csv={{
                headers: ['Line Item', ...active.years.map((y) => fyLabel(y.fiscalYear))],
                rows: opPLRows.map((row) => [
                  row.label,
                  ...active.years.map((y) => (y as never)[row.key] as number),
                ]) as (string | number)[][],
              }}
            />
            {(['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) => {
              const titleByScenario: Record<ScenarioName, string> = {
                Base: 'Base: 6.5% mean annual market return through FY35 (DC CAP default; editable in the Market sub-tab of the Inputs panel)',
                Optimistic: 'Optimistic: 8.0% mean annual market return through FY35 (editable in the Market sub-tab of the Inputs panel)',
                Pessimistic: 'Pessimistic: −10% FY27/FY28 drawdown, +8% recovery FY29/FY30, 6.5% steady-state FY31–FY35. Carries the stress-test work the retired Monte Carlo tab used to do.',
              };
              return (
                <button
                  key={s}
                  onClick={() => setScenario(s)}
                  title={titleByScenario[s]}
                  className={`tab-btn ${scenario === s ? 'tab-btn-active' : ''}`}
                >
                  {s}
                </button>
              );
            })}
          </div>
        </div>
        <div className="card-body overflow-x-auto">
          <div className="eyebrow mb-2">Operating P&amp;L</div>
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/65 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Operating P&amp;L</th>
                {active.years.map((y) => (
                  <th key={y.fiscalYear} className="text-right px-3 py-2 font-semibold">
                    {fyLabel(y.fiscalYear)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {opPLRows.map((row) => (
                <tr
                  key={row.key}
                  className={
                    'emphasis' in row && row.emphasis
                      ? 'bg-tan/60 border-y-2 border-navy/80 font-semibold'
                      : 'border-b border-navy/5'
                  }
                >
                  <td className="text-left py-2 pr-4 text-navy align-top">
                    <div>{row.label}</div>
                    {'sub' in row && row.sub && (
                      <div className="text-xs text-navy/55 font-sub font-normal mt-0.5">
                        {row.sub}
                      </div>
                    )}
                    {'hint' in row && row.hint && (
                      <div className="text-xs text-navy/55 font-sub font-normal mt-0.5 italic">
                        {row.hint}
                      </div>
                    )}
                  </td>
                  {active.years.map((y, yIdx) => {
                    const isFy27 = yIdx === 0;
                    const showFy27Annotation =
                      isFy27 && 'fy27Composition' in row && row.fy27Composition;
                    return (
                      <td
                        key={y.fiscalYear}
                        className="text-right px-3 py-2 text-navy align-top"
                      >
                        <div>{dollars((y as never)[row.key] as number)}</div>
                        {showFy27Annotation && (
                          <div className="text-[11px] text-navy/65 font-sub font-normal mt-2 leading-snug border-l-2 border-tan pl-2 text-left max-w-[14rem]">
                            <span className="font-semibold text-navy">
                              FY27 only:
                            </span>{' '}
                            {row.fy27Composition}
                          </div>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))}
              {opPLMemoRows.map((row) => (
                <tr key={row.label} className="border-b border-navy/5 text-navy/70 italic">
                  <td className="text-left py-2 pr-4 align-top">
                    <div className="text-xs">{row.label}</div>
                    {row.hint && (
                      <div className="text-xs text-navy/55 font-sub not-italic mt-0.5">
                        {row.hint}
                      </div>
                    )}
                  </td>
                  {active.years.map((y) => (
                    <td key={y.fiscalYear} className="text-right px-3 py-2 text-xs">
                      {dollars(row.compute(y))}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
          <p className="text-[11px] text-navy/65 font-sub italic mt-3 leading-snug">
            <span className="font-semibold not-italic text-navy">*</span> FY27
            values reflect Finance's <strong className="not-italic">DRAFT FY27
            budget</strong> (DCCAP 2027-00 Budget DRAFT Preview.xlsx, saved
            2026-05-15). Pending Board approval — final figures may revise
            before adoption. FY28/FY29 outyear values are from the same DRAFT
            file. FY30–FY35 are model extrapolation (carry-forward + assumed
            growth rates) — see the Assumptions tab.
          </p>
        </div>

        <div className="card-body border-t border-navy/10 overflow-x-auto">
          <div className="eyebrow mb-2">Endowment activity (balance evolution)</div>
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/65 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Endowment activity</th>
                {active.years.map((y) => (
                  <th key={y.fiscalYear} className="text-right px-3 py-2 font-semibold">
                    {fyLabel(y.fiscalYear)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {endowmentActivityRows.map((row) => (
                <tr
                  key={row.key}
                  className={
                    'emphasis' in row && row.emphasis
                      ? 'bg-tan/60 border-y-2 border-navy/80 font-semibold'
                      : 'border-b border-navy/5'
                  }
                >
                  <td className="text-left py-2 pr-4 text-navy">{row.label}</td>
                  {active.years.map((y) => (
                    <td key={y.fiscalYear} className="text-right px-3 py-2 text-navy">
                      {formatSigned((y as never)[row.key] as number, row.sign as -1 | 0 | 1)}
                    </td>
                  ))}
                </tr>
              ))}
              {memoRows.map((row) => (
                <tr key={row.key} className="border-b border-navy/5 text-navy/70 italic">
                  <td className="text-left py-2 pr-4 align-top">
                    <div className="text-xs">{row.label}</div>
                    {'hint' in row && row.hint && (
                      <div className="text-xs text-navy/55 font-sub not-italic mt-0.5">
                        {row.hint}
                      </div>
                    )}
                  </td>
                  {active.years.map((y) => {
                    const raw = (y as never)[row.key] as number;
                    const text =
                      row.format === 'percent' ? percent(raw, 2) : dollars(raw);
                    return (
                      <td key={y.fiscalYear} className="text-right px-3 py-2 text-xs">
                        {text}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <section ref={policyRateRef} className="card">
        <div className="card-header flex items-center justify-between flex-wrap gap-2">
          <div>
            <div className="eyebrow">Policy-rate trajectory · NACUBO peer-band overlay</div>
            <h2 className="font-head text-base">
              {scenario} scenario · draw ÷ 3-yr rolling avg
            </h2>
          </div>
          <ExportButton
            targetRef={policyRateRef}
            filename={`policy-rate-${scenario.toLowerCase()}`}
            csv={{
              headers: ['Fiscal Year', `${scenario} Policy Rate (%)`, 'NACUBO P25', 'NACUBO Median', 'NACUBO P75'],
              rows: policyRateChartData.map((d) => [
                d.fiscalYear,
                d.policyRatePct.toFixed(3),
                (NACUBO_PEER_BANDS.P25 * 100).toFixed(1),
                (NACUBO_PEER_BANDS.MEDIAN * 100).toFixed(1),
                (NACUBO_PEER_BANDS.P75 * 100).toFixed(1),
              ]) as (string | number)[][],
            }}
          />
        </div>
        <div className="card-body">
          <div
            className="h-[280px]"
            role="img"
            aria-label={`Implied policy-rate trajectory for the ${scenario} scenario. FY27 starts at ${(active.years[0].policyRate * 100).toFixed(2)} percent — above the NACUBO P75 ${(NACUBO_PEER_BANDS.P75 * 100).toFixed(1)} percent threshold — then settles to ${(active.years[active.years.length - 1].policyRate * 100).toFixed(2)} percent by FY${String(active.years[active.years.length - 1].fiscalYear).slice(-2)}. Green shaded band marks the NACUBO P25 to P75 typical peer range (${(NACUBO_PEER_BANDS.P25 * 100).toFixed(1)} to ${(NACUBO_PEER_BANDS.P75 * 100).toFixed(1)} percent); dashed line marks the NACUBO median ${(NACUBO_PEER_BANDS.MEDIAN * 100).toFixed(1)} percent.`}
          >
            <ResponsiveContainer width="100%" height="100%">
              <LineChart
                data={policyRateChartData}
                margin={{ top: 16, right: 24, bottom: 8, left: 0 }}
              >
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C20" />
                <XAxis
                  dataKey="fiscalYear"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(fy) => fyLabel(Number(fy))}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `${Number(v).toFixed(1)}%`}
                  stroke="#101A4C40"
                  width={56}
                  domain={[0, 'dataMax + 1']}
                />
                {/* NACUBO P25 → P75 typical band — green for "in peer norms" */}
                <ReferenceArea
                  y1={NACUBO_PEER_BANDS.P25 * 100}
                  y2={NACUBO_PEER_BANDS.P75 * 100}
                  fill="#2d8268"
                  fillOpacity={0.10}
                  strokeOpacity={0}
                  ifOverflow="extendDomain"
                  label={{
                    value: 'NACUBO P25 → P75 (typical peer band)',
                    position: 'insideTopRight',
                    fill: '#2d8268',
                    fontSize: 10,
                    fontFamily: 'Noto Serif SemiCondensed, serif',
                  }}
                />
                {/* NACUBO median reference line — the headline peer benchmark */}
                <ReferenceLine
                  y={NACUBO_PEER_BANDS.MEDIAN * 100}
                  stroke="#2d8268"
                  strokeDasharray="4 4"
                  strokeOpacity={0.55}
                  label={{
                    value: `NACUBO median ${(NACUBO_PEER_BANDS.MEDIAN * 100).toFixed(1)}%`,
                    position: 'insideBottomRight',
                    fill: '#2d8268',
                    fontSize: 10,
                    fontFamily: 'Noto Serif SemiCondensed, serif',
                  }}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  itemStyle={{ color: '#101A4C' }}
                  labelStyle={{ color: '#101A4C', fontWeight: 600 }}
                  formatter={(v) => `${Number(v).toFixed(2)}%`}
                  labelFormatter={(fy) => fyLabel(Number(fy))}
                />
                <Line
                  type="monotone"
                  dataKey="policyRatePct"
                  name={`${scenario} policy rate`}
                  stroke={SCENARIO_COLORS[scenario] ?? SCENARIO_COLORS.Base}
                  strokeWidth={2.5}
                  dot={{ r: 4 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
          <p className="mt-3 text-xs text-navy/70 font-sub leading-snug">
            <span className="font-semibold text-navy">Peer band source:</span>{' '}
            NACUBO-Commonfund 2024 Study of Endowments — spending-rate distribution
            across ~700 endowments. The typical (P25 → P75) band sits around{' '}
            {(NACUBO_PEER_BANDS.P25 * 100).toFixed(1)}% –{' '}
            {(NACUBO_PEER_BANDS.P75 * 100).toFixed(1)}% with the median near{' '}
            {(NACUBO_PEER_BANDS.MEDIAN * 100).toFixed(1)}%.
          </p>
          {(() => {
            const fy27 = active.years[0];
            const fy35 = active.years[active.years.length - 1];
            const troughIdx = active.years.reduce(
              (best, y, i) =>
                y.policyRate < active.years[best].policyRate ? i : best,
              0
            );
            const trough = active.years[troughIdx];
            const inBand = (r: number) =>
              r >= NACUBO_PEER_BANDS.P25 && r <= NACUBO_PEER_BANDS.P75;
            const aboveP75 = (r: number) => r > NACUBO_PEER_BANDS.P75;
            const belowMedian = (r: number) => r < NACUBO_PEER_BANDS.MEDIAN;
            const divergentEnd =
              aboveP75(fy35.policyRate) && trough.policyRate < fy35.policyRate;

            if (scenario === 'Base') {
              return (
                <p className="mt-2 text-xs text-navy/65 font-sub leading-snug">
                  <span className="font-semibold text-navy">FY27 trough story:</span>{' '}
                  FY27's headline {percent(fy27.policyRate, 2)} sits above the
                  NACUBO P75 because scholarship commitments peak in the first
                  year before stepping down. Trajectory troughs at{' '}
                  {percent(trough.policyRate, 2)} in {fyLabel(trough.fiscalYear)}{' '}
                  — inside the NACUBO P25–P75 band — then drifts to{' '}
                  {percent(fy35.policyRate, 2)} by {fyLabel(fy35.fiscalYear)}.
                </p>
              );
            }

            if (scenario === 'Optimistic') {
              const endingPhrase = belowMedian(fy35.policyRate)
                ? 'below the NACUBO median'
                : inBand(fy35.policyRate)
                ? 'inside the NACUBO P25–P75 band'
                : 'still above the NACUBO P75';
              return (
                <p className="mt-2 text-xs text-navy/65 font-sub leading-snug">
                  <span className="font-semibold text-navy">Upside story:</span>{' '}
                  Sustained {(inputs.marketReturn.Optimistic[0]).toFixed(1)}%
                  returns compound the endowment faster than the residual draw
                  scales. Policy rate troughs at {percent(trough.policyRate, 2)}{' '}
                  in {fyLabel(trough.fiscalYear)} and settles near{' '}
                  {percent(fy35.policyRate, 2)} by {fyLabel(fy35.fiscalYear)} —{' '}
                  {endingPhrase} in this scenario.
                </p>
              );
            }

            // Pessimistic — divergence framing when policy rate climbs back
            // above NACUBO P75 in the terminal years even though the balance
            // hasn't broken the $40M going-concern floor.
            if (divergentEnd) {
              return (
                <p className="mt-2 text-xs text-[#C8395B] font-sub leading-snug">
                  <span className="font-semibold">Divergence warning:</span>{' '}
                  Pessimistic drawdowns ({inputs.marketReturn.Pessimistic[0]}%
                  FY27 · {inputs.marketReturn.Pessimistic[1]}% FY28) leave a
                  permanently smaller endowment. Policy rate troughs at{' '}
                  {percent(trough.policyRate, 2)} in {fyLabel(trough.fiscalYear)}{' '}
                  as scholarships step down, then climbs back through P75 and
                  reaches {percent(fy35.policyRate, 2)} by{' '}
                  {fyLabel(fy35.fiscalYear)} — operating draw becomes
                  unsustainable in this scenario even with the balance staying
                  above the {fmtMillions(RUNWAY_FLOOR_BALANCE)} floor. The math
                  is signaling stress even when the going-concern banner is
                  quiet.
                </p>
              );
            }
            return (
              <p className="mt-2 text-xs text-navy/65 font-sub leading-snug">
                <span className="font-semibold text-navy">Stress trajectory:</span>{' '}
                Pessimistic drawdowns leave a smaller endowment but the policy
                rate settles at {percent(fy35.policyRate, 2)} by{' '}
                {fyLabel(fy35.fiscalYear)} —{' '}
                {inBand(fy35.policyRate)
                  ? 'inside the NACUBO P25–P75 band'
                  : 'within range of recovery'}{' '}
                under these market inputs.
              </p>
            );
          })()}
        </div>
      </section>
    </div>
  );
}

const HOW_TO_READ_STORAGE_KEY = 'dccap-fm-how-to-read-open';

function HowToReadThisView() {
  // Default-open on first visit; persist user's collapse choice across sessions.
  const [open, setOpen] = useState<boolean>(() => {
    if (typeof window === 'undefined') return true;
    const stored = window.localStorage.getItem(HOW_TO_READ_STORAGE_KEY);
    return stored === null ? true : stored === 'true';
  });

  const handleToggle = useCallback((e: React.SyntheticEvent<HTMLDetailsElement>) => {
    const next = e.currentTarget.open;
    setOpen(next);
    try {
      window.localStorage.setItem(HOW_TO_READ_STORAGE_KEY, String(next));
    } catch {
      // Private-mode browsers may block localStorage; degrade gracefully.
    }
  }, []);

  return (
    <section className="card">
      <details open={open} onToggle={handleToggle}>
        <summary className="card-body text-sm font-semibold text-navy cursor-pointer marker:text-purple list-revert select-none">
          How to read this view
        </summary>
        <div className="card-body pt-0 text-sm text-navy/85 font-sub">
          <p>
            FY27 numbers are anchored to Finance's <strong>DRAFT May 2026 budget</strong>*
            (pending Board approval). This is the most current source of
            truth from Finance, but figures may revise before the formal
            Board vote. DC CAP sizes the endowment draw to what's needed
            each year (total expenses minus operating revenue); the implied
            policy rate (draw ÷ 3-yr rolling avg) is a diagnostic that
            emerges, not a knob. Market return appears only in the Endowment
            Activity table, never as operating income.
          </p>
          <p className="mt-2 text-xs text-navy/65">
            <span className="font-semibold text-navy">Pre-Booked AOR timing:</span>{' '}
            $3.87M of multi-year pledges sit on the books from prior years'
            raise. Of that, $1.87M releases to FY27 P&amp;L (the "Releases
            from AOR" line in operating revenue); the remaining $2.00M is
            deferred to FY28+ P&amp;Ls. The FY27 endowment "gap" is the
            $7.43M residual after BOTH new fundraising and pre-booked
            releases — not the full $3.87M of pledges on the books.
          </p>
          <p className="mt-2 text-xs text-navy/65">
            <span className="font-semibold text-navy">Dev Office overlay:</span>{' '}
            The FY27 Pipeline tab tracks the operational raise plan and
            reconciles to these budget lines. The Pipeline Tool's segment tabs
            are canonical; its Summary tab's top cross-segment block (R6–R9)
            is known-inconsistent and disregarded.
          </p>
        </div>
      </details>
    </section>
  );
}
