import { useEffect, useMemo, useState } from 'react';
import {
  fetchBudget,
  type Budget,
  type ProvenanceMap,
  type SourceCell,
} from '../../lib/budget';
import {
  runRuntimeVerification,
  type VerificationCheck,
  type VerificationReport,
} from '../../lib/verification';
import type { FinancialInputs } from '../../lib/model';

interface Props {
  budget: Budget | null;
  inputs: FinancialInputs;
}

const LAYER_LABELS: Record<VerificationCheck['layer'], string> = {
  'L2-parser': 'L2 · Parser hard-gate (build time)',
  'L3-runtime': 'L3 · Runtime cross-foots (browser load)',
  'L4-defaults': 'L4 · Model defaults alignment',
};

const LAYER_ORDER: VerificationCheck['layer'][] = [
  'L2-parser',
  'L3-runtime',
  'L4-defaults',
];

function statusPill(passed: boolean, severity: VerificationCheck['severity']) {
  if (passed) {
    return (
      <span className="inline-block px-2 py-0.5 rounded text-xs font-head uppercase tracking-wide-15 bg-emerald-100 text-emerald-800">
        Pass
      </span>
    );
  }
  if (severity === 'advisory') {
    return (
      <span className="inline-block px-2 py-0.5 rounded text-xs font-head uppercase tracking-wide-15 bg-amber-100 text-amber-800">
        Advisory
      </span>
    );
  }
  return (
    <span className="inline-block px-2 py-0.5 rounded text-xs font-head uppercase tracking-wide-15 bg-rose-100 text-rose-800">
      FAIL
    </span>
  );
}

function HeadlineStatus({ report }: { report: VerificationReport }) {
  const { passed, summary } = report;
  if (passed && summary.advisoryFailed === 0) {
    return (
      <div className="bg-emerald-50 border border-emerald-200 text-emerald-900 px-4 py-3 rounded">
        <strong className="font-head uppercase tracking-wide-15 text-sm">
          All gates green
        </strong>{' '}
        — {summary.passed} of {summary.total} checks pass. Every number in this
        tool reconciles to the Budget Preview.
      </div>
    );
  }
  if (passed) {
    return (
      <div className="bg-emerald-50 border border-emerald-200 text-emerald-900 px-4 py-3 rounded">
        <strong className="font-head uppercase tracking-wide-15 text-sm">
          Hard gates green; {summary.advisoryFailed} advisory drift
        </strong>{' '}
        — {summary.passed} of {summary.total} checks pass. No blockers; review
        advisories below.
      </div>
    );
  }
  return (
    <div className="bg-rose-50 border border-rose-300 text-rose-900 px-4 py-3 rounded">
      <strong className="font-head uppercase tracking-wide-15 text-sm">
        {summary.hardFailed} hard gate{summary.hardFailed === 1 ? '' : 's'} failing
      </strong>{' '}
      — the tool is rendering numbers that don't reconcile. Treat output as
      provisional until resolved.
    </div>
  );
}

function FileMetadata({ budget }: { budget: Budget }) {
  const saved = new Date(budget.meta.fileLastModified).toLocaleString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
  const synced = new Date(budget.meta.syncedAt).toLocaleString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
  const rows: [string, string][] = [
    ['Source file', budget.meta.sourceFile],
    ['Source path', budget.meta.sourceUrl],
    ['File saved at', saved],
    ['Parser synced at', synced],
    ['Schema version', `v${budget.meta.schemaVersion}`],
    ['View', budget.meta.view],
    ['Provenance entries', String(Object.keys(budget.provenance).length)],
  ];
  return (
    <article className="bg-white rounded shadow-sm p-6">
      <h2 className="font-head uppercase tracking-wide-15 text-navy text-sm mb-3">
        Source File Metadata
      </h2>
      <dl className="grid grid-cols-1 sm:grid-cols-2 gap-x-6 gap-y-2 text-sm">
        {rows.map(([label, val]) => (
          <div key={label} className="flex justify-between gap-3 border-b border-navy/10 py-1">
            <dt className="text-navy/60">{label}</dt>
            <dd className="font-mono text-navy text-xs text-right truncate" title={val}>
              {val}
            </dd>
          </div>
        ))}
      </dl>
      {budget.meta.leaseEndsAnnotation && (
        <p className="text-xs text-navy/60 mt-3">
          <strong>Annotation:</strong> {budget.meta.leaseEndsAnnotation}
        </p>
      )}
    </article>
  );
}

function ChecksTable({
  checks,
  layer,
}: {
  checks: VerificationCheck[];
  layer: VerificationCheck['layer'];
}) {
  const layerChecks = checks.filter((c) => c.layer === layer);
  if (layerChecks.length === 0) return null;

  const passed = layerChecks.filter((c) => c.passed).length;
  const total = layerChecks.length;
  const allPassed = passed === total;

  return (
    <article className="bg-white rounded shadow-sm overflow-hidden">
      <header className="px-6 py-3 border-b border-navy/10 flex items-center justify-between">
        <h2 className="font-head uppercase tracking-wide-15 text-navy text-sm">
          {LAYER_LABELS[layer]}
        </h2>
        <span
          className={`text-xs font-head uppercase tracking-wide-15 ${
            allPassed ? 'text-emerald-700' : 'text-rose-700'
          }`}
        >
          {passed} / {total} pass
        </span>
      </header>
      <table className="w-full text-sm">
        <thead className="bg-tan/40">
          <tr className="text-navy/60 text-xs font-head uppercase tracking-wide-15">
            <th className="text-left px-4 py-2 w-20">Status</th>
            <th className="text-left px-4 py-2">Check</th>
            <th className="text-left px-4 py-2 hidden md:table-cell">Detail</th>
          </tr>
        </thead>
        <tbody className="text-navy">
          {layerChecks.map((c, i) => (
            <tr key={`${c.layer}-${i}`} className="border-t border-navy/10">
              <td className="px-4 py-2 align-top">
                {statusPill(c.passed, c.severity)}
              </td>
              <td className="px-4 py-2 align-top">{c.name}</td>
              <td className="px-4 py-2 align-top hidden md:table-cell font-mono text-xs text-navy/80">
                {c.detail}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </article>
  );
}

function ProvenanceLookup({ provenance }: { provenance: ProvenanceMap }) {
  const [query, setQuery] = useState('');
  const entries = useMemo(() => Object.entries(provenance), [provenance]);
  const filtered = useMemo(() => {
    if (!query.trim()) return entries.slice(0, 20);
    const q = query.toLowerCase();
    return entries
      .filter(([path, src]) =>
        path.toLowerCase().includes(q) ||
        src.sheet.toLowerCase().includes(q) ||
        src.cellAddress.toLowerCase().includes(q)
      )
      .slice(0, 50);
  }, [entries, query]);

  return (
    <article className="bg-white rounded shadow-sm overflow-hidden">
      <header className="px-6 py-3 border-b border-navy/10">
        <h2 className="font-head uppercase tracking-wide-15 text-navy text-sm">
          Provenance Lookup ({entries.length} paths)
        </h2>
        <p className="text-xs text-navy/60 mt-1">
          Search any logical path (e.g. <code className="bg-tan/60 px-1 rounded">payroll</code>,{' '}
          <code className="bg-tan/60 px-1 rounded">fy29</code>) or sheet name. Each row resolves
          to a single Budget Preview cell so any number on this site can be traced back to its
          origin.
        </p>
        <input
          type="search"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Filter paths or sheets…"
          className="mt-3 w-full px-3 py-2 border border-navy/20 rounded text-sm focus:outline-none focus:ring-2 focus:ring-purple/50"
        />
      </header>
      <div className="max-h-96 overflow-y-auto">
        <table className="w-full text-sm">
          <thead className="bg-tan/40 sticky top-0">
            <tr className="text-navy/60 text-xs font-head uppercase tracking-wide-15">
              <th className="text-left px-4 py-2">Logical Path</th>
              <th className="text-left px-4 py-2">Sheet</th>
              <th className="text-left px-4 py-2">Cell</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map(([path, src]: [string, SourceCell]) => (
              <tr key={path} className="border-t border-navy/10 hover:bg-tan/30">
                <td className="px-4 py-1.5 font-mono text-xs">{path}</td>
                <td className="px-4 py-1.5 text-xs">{src.sheet}</td>
                <td className="px-4 py-1.5 font-mono text-xs">
                  {src.cellAddress}
                </td>
              </tr>
            ))}
            {filtered.length === 0 && (
              <tr>
                <td colSpan={3} className="px-4 py-6 text-center text-navy/50 text-xs">
                  No matches.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
      {!query && entries.length > 20 && (
        <div className="px-4 py-2 text-xs text-navy/60 border-t border-navy/10 bg-tan/20">
          Showing first 20 of {entries.length}. Type to filter.
        </div>
      )}
    </article>
  );
}

export function Verification({ budget, inputs }: Props) {
  const [internalBudget, setInternalBudget] = useState<Budget | null>(budget);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (budget) {
      setInternalBudget(budget);
      return;
    }
    fetchBudget()
      .then(setInternalBudget)
      .catch((e: Error) => setError(e.message));
  }, [budget]);

  const report = useMemo(
    () => runRuntimeVerification(internalBudget, inputs),
    [internalBudget, inputs]
  );

  if (error) {
    return (
      <section className="bg-rose-50 border border-rose-300 text-rose-900 p-6 rounded">
        <strong>Cannot run verification — budget.json failed to load:</strong>{' '}
        {error}
      </section>
    );
  }

  if (!internalBudget) {
    return (
      <section className="bg-white p-6 rounded shadow-sm">
        <p className="text-navy/60">Loading verification report…</p>
      </section>
    );
  }

  return (
    <section className="space-y-6">
      <header className="bg-white p-6 rounded shadow-sm">
        <h1 className="font-head uppercase tracking-wide-15 text-navy text-xl">
          Verification · Source Reconciliation
        </h1>
        <p className="font-sub text-navy/70 mt-2">
          Defense-in-depth check that every number rendered by this tool
          reconciles to the Budget Preview file. Four layers — L1 source-cell
          provenance, L2 parser hard-gate (run at build time), L3 runtime
          cross-foots (run on every page load), L4 model defaults alignment.
        </p>
        <div className="mt-4">
          <HeadlineStatus report={report} />
        </div>
        <dl className="mt-4 grid grid-cols-2 sm:grid-cols-4 gap-3 text-sm">
          <div className="bg-tan/50 px-3 py-2 rounded">
            <dt className="text-xs uppercase tracking-wide-15 text-navy/60 font-head">
              Total Checks
            </dt>
            <dd className="font-mono text-lg text-navy">
              {report.summary.total}
            </dd>
          </div>
          <div className="bg-emerald-50 px-3 py-2 rounded">
            <dt className="text-xs uppercase tracking-wide-15 text-emerald-700 font-head">
              Passing
            </dt>
            <dd className="font-mono text-lg text-emerald-900">
              {report.summary.passed}
            </dd>
          </div>
          <div className="bg-rose-50 px-3 py-2 rounded">
            <dt className="text-xs uppercase tracking-wide-15 text-rose-700 font-head">
              Hard Failures
            </dt>
            <dd className="font-mono text-lg text-rose-900">
              {report.summary.hardFailed}
            </dd>
          </div>
          <div className="bg-amber-50 px-3 py-2 rounded">
            <dt className="text-xs uppercase tracking-wide-15 text-amber-700 font-head">
              Advisories
            </dt>
            <dd className="font-mono text-lg text-amber-900">
              {report.summary.advisoryFailed}
            </dd>
          </div>
        </dl>
      </header>

      <FileMetadata budget={internalBudget} />

      {LAYER_ORDER.map((layer) => (
        <ChecksTable key={layer} checks={report.checks} layer={layer} />
      ))}

      <ProvenanceLookup provenance={internalBudget.provenance} />
    </section>
  );
}
