// DC CAP financial model — FY27 baseline, budget-aligned (May 2026 Board-approved budget).
// Pure functions. No DOM, no React. Fully unit-testable.
//
// Window: FY27 → FY35 (9 years). Historical chart context: FY15 → FY26.
// All monetary values are stored in dollars (not millions). UI converts at the boundary.
//
// Model semantics (post-budget integration, 2026-05-13; draw-as-residual corrected 2026-05-13):
//
//   Operating side (P&L) — budget identity is balanced by construction
//     operatingRevenue   = gifts + grants + events + contributed + AOR releases
//     totalExpenses      = awardCosts + opExpenses
//     endowmentDraw      = max(0, totalExpenses − operatingRevenue)   // residual financing
//     totalRevenue       = operatingRevenue + endowmentDraw
//     operatingNetIncome = totalRevenue − totalExpenses               // = 0 by construction
//
//   Balance side
//     marketAppreciation     = beginningEndowment × marketReturnPct
//     endingEndowment        = beginningEndowment + marketAppreciation
//                              − endowmentDraw + additionsToEndowment
//
//   Diagnostic rates (emerge from the math, not inputs)
//     policyRate = endowmentDraw / rollingAverageBalance       // NACUBO/CommonFund denominator
//     actualRate = endowmentDraw / beginningEndowment          // financial-statement denominator
//
// Why residual, not rate-driven: DC CAP sizes the draw to the operating need each year.
// The FY27 implied rate of 10.34% (3-yr basis) is what falls out — not a policy lever we
// crank. As scholarships step down and op-ex creeps, the needed draw bends with them,
// and the implied rate bends with both numerator (need) and denominator (rolling avg).

export type ScenarioName = 'Base' | 'Optimistic' | 'Pessimistic';

export interface PhilanthropicYear {
  /** Locked, signed gifts and pledges already counted as revenue. */
  committed: number;
  /** Reasonable likelihood — renewals from existing donors, late-stage proposals. */
  likely: number;
  /** Unfilled portion of the operating-revenue target. The "to-find" closing problem. */
  gap: number;
}

export interface FinancialInputs {
  /** Beginning endowment for the first year of the projection window (FY27). */
  beginningEndowment: number;
  /** Award (scholarship) costs by year (FY27 → FY35), in dollars. */
  awardCosts: number[];
  /** Operating expense baseline for FY27. Subsequent years grow at opExpensesGrowth. */
  opExpensesInit: number;
  /** Annual operating expense growth rate, percent (e.g., 3 means 3%). */
  opExpensesGrowth: number;
  /** One-time op-expense reduction year (1-indexed). FY27=1, FY28=2, FY29=3, etc. */
  opExpensesReductionYear: number;
  /** One-time op-expense reduction amount, in dollars (cut persists permanently). */
  opExpensesReductionAmount: number;
  /**
   * Per-year op-expense override (FY27 → FY35). When a value at index i is a
   * finite number, it replaces the compounded calculation for that year; when
   * `null` or missing, the compounded calculation is used. This is how the
   * model honors the Budget Preview's FY27/FY28/FY29 line-item projections,
   * which don't follow a simple growth-from-baseline curve (payroll moves with
   * GEAR UP cycling, rent steps when the lease ends, etc.).
   */
  opExpensesOverride?: (number | null)[];
  /**
   * Operating revenue per year (FY27 → FY35), in dollars.
   * Semantics post-2026-05-13: gifts + grants + events + contributed + AOR releases that
   * hit the P&L this year. **Excludes principal additions to the endowment**
   * (those go in `additionsToEndowment`).
   *
   * NOTE: The field is named `fundraising` for backward-compatibility with prior
   * versions of the tool, but its meaning has changed from "total fundraising target"
   * to "operating revenue." Renames are deferred to a follow-up commit so saved
   * inputs continue to work.
   */
  fundraising: number[];
  /**
   * Principal additions to endowment per year (FY27 → FY35), in dollars.
   * Restricted gifts directed to the corpus rather than operating P&L.
   * Default $2M/yr (FY27 budget R31, flat thereafter).
   */
  additionsToEndowment: number[];
  /**
   * Prior-year ending balances used to seed the 3-yr rolling average for FY27's draw.
   * Order: [FY24, FY25, FY26]. Subsequent years extend with the projection's own
   * ending balances.
   */
  priorYearBalances: number[];
  /** Per-year philanthropic decomposition. Length matches projection window. */
  philanthropic: PhilanthropicYear[];
  /** Annual market return assumptions per scenario, percent. Length matches window. */
  marketReturn: Record<ScenarioName, number[]>;
}

export interface YearMetrics {
  fiscalYear: number;
  beginningEndowment: number;

  // === Operating side (P&L) ===
  /** Operating revenue: gifts + grants + events + contributed + releases. */
  operatingRevenue: number;
  /** Endowment draw applied this year — sized as the residual to balance the budget. */
  endowmentDraw: number;
  /** operatingRevenue + endowmentDraw. */
  totalRevenue: number;
  awardCosts: number;
  opExpenses: number;
  totalExpenses: number;
  /** totalRevenue − totalExpenses. Target ≈ 0 (balanced budget). */
  operatingNetIncome: number;

  // === Balance side ===
  /** 3-year rolling average of prior ending balances — denominator for the policy-rate diagnostic. */
  rollingAverageBalance: number;
  /** beginningEndowment × marketReturnPct (return contribution to balance). */
  marketAppreciation: number;
  /** Principal additions to endowment this year. */
  additionsToEndowment: number;
  /** beg + marketAppreciation − endowmentDraw + additionsToEndowment. */
  endingEndowment: number;

  // === Diagnostic draw rates ===
  /** endowmentDraw ÷ rollingAverageBalance (policy rate, NACUBO/CommonFund). */
  policyRate: number;
  /** endowmentDraw ÷ beginningEndowment (actual rate, financial-statement view). */
  actualRate: number;

  // === Back-compat aliases (deprecated; retire after UI fully migrated) ===
  /** @deprecated Use operatingRevenue. */
  fundraising: number;
  /** @deprecated Use marketAppreciation. */
  marketReturn: number;
  /** @deprecated Use totalRevenue. */
  totalIncome: number;
  /** @deprecated Use operatingNetIncome. */
  totalPL: number;
  /** @deprecated Use policyRate (preferred) or actualRate. Semantic is now policy rate vs rolling avg. */
  spendRate: number;
}

export interface ScenarioProjection {
  scenario: ScenarioName;
  years: YearMetrics[];
}

// --- Constants ---

export const PROJECTION_START_FY = 2027;
export const PROJECTION_END_FY = 2035;
export const PROJECTION_LENGTH = PROJECTION_END_FY - PROJECTION_START_FY + 1; // 9

/**
 * Trailing rolling-window for endowment draw policy.
 * 3-year chosen over 5-year because DC CAP's endowment recently grew from ~$48M to ~$100M
 * (FY26 major gift). The 5-yr basis suppresses the denominator and lags the new capacity.
 * The 5-yr value is computed only as a display-only comparator for budget reconciliation
 * (the Board-approved budget uses a 5-yr basis).
 */
export const ROLLING_WINDOW_YEARS = 3;

/** Comparator window for budget reconciliation only — never drives the live model. */
export const COMPARATOR_WINDOW_YEARS = 5;

