// --- Helpers ---

export function fiscalYears(): number[] {
  const out: number[] = [];
  for (let y = PROJECTION_START_FY; y <= PROJECTION_END_FY; y++) out.push(y);
  return out;
}

/**
 * Mean of the most recent `years` entries in `balances`. If fewer entries are
 * available, averages whatever is present. Returns 0 on empty input.
 */
export function rollingAverage(balances: number[], years: number): number {
  if (balances.length === 0) return 0;
  const slice = balances.slice(-years);
  return slice.reduce((a, b) => a + b, 0) / slice.length;
}

/**
 * Compute operating expenses for a given year index (0-based) using iterative
 * compounding. When the one-time reduction kicks in (e.g., FY29 lease end), the
 * lower base persists — all subsequent years compound from the cut value.
 */
export function opExpensesAtYear(
  yearIdx: number,
  init: number,
  growthPct: number,
  reductionYear: number,
  reductionAmount: number
): number {
  let val = reductionYear === 1 ? init - reductionAmount : init;
  for (let i = 1; i <= yearIdx; i++) {
    val = val * (1 + growthPct / 100);
    if (i + 1 === reductionYear) val -= reductionAmount;
  }
  return val;
}

/**
 * Roll one scenario forward across the projection window. Pure: takes inputs,
 * returns fully-populated YearMetrics for each year.
 *
 * Math: operating P&L is separated from balance evolution. The endowment draw is
 * sized against the trailing 3-yr rolling average of ending balances (seeded by
 * priorYearBalances). See module docstring for the full identity.
 */
export function projectScenario(
  inputs: FinancialInputs,
  scenario: ScenarioName
): ScenarioProjection {
  const years = fiscalYears();
  const out: YearMetrics[] = [];

  // History buffer: priorYearBalances + each year's ending as we compute it.
  // Used to compute the rolling average for the NEXT year. FY27's rolling avg
  // is the mean of priorYearBalances[-3:] (i.e., FY24/FY25/FY26 endings).
  const balanceHistory: number[] = [...inputs.priorYearBalances];
  let beg = inputs.beginningEndowment;

  // Carry-forward state for op-ex compounding. When opExpensesOverride is
  // populated for years 0..N (Budget Preview era) and null thereafter, we
  // compound forward from the LAST override value — growth only, no further
  // scheduled reduction (the lease-end / one-time cut is presumed baked into
  // the override values, since the Budget Preview already reflects it).
  let lastOpEx: number | null = null;
  let usedAnOverride = false;

  for (let i = 0; i < years.length; i++) {
    const fy = years[i];

    // Operating side
    const operatingRevenue = inputs.fundraising[i] ?? 0;
    const awardCosts = inputs.awardCosts[i] ?? 0;
    const override = inputs.opExpensesOverride?.[i];
    let opExpenses: number;
    if (typeof override === 'number' && Number.isFinite(override)) {
      opExpenses = override;
      usedAnOverride = true;
    } else if (usedAnOverride && lastOpEx !== null) {
      // Carry forward: budget data has been exhausted, compound growth from
      // the last override value. No reduction reapplied — the FY29 override
      // already includes the lease-end drop.
      opExpenses = lastOpEx * (1 + inputs.opExpensesGrowth / 100);
    } else {
      // No overrides have been seen yet — fall back to the standalone compound
      // calc rooted at opExpensesInit, with reductionYear applied normally.
      opExpenses = opExpensesAtYear(
        i,
        inputs.opExpensesInit,
        inputs.opExpensesGrowth,
        inputs.opExpensesReductionYear,
        inputs.opExpensesReductionAmount
      );
    }
    lastOpEx = opExpenses;
    const totalExpenses = awardCosts + opExpenses;

    // Draw is residual financing — sized to balance the budget. The rate emerges as
    // a diagnostic (policyRate / actualRate below), it is not an input.
    const rollingAvg = rollingAverage(balanceHistory, ROLLING_WINDOW_YEARS);
    const endowmentDraw = Math.max(0, totalExpenses - operatingRevenue);
    const totalRevenue = operatingRevenue + endowmentDraw;
    const operatingNetIncome = totalRevenue - totalExpenses;

    // Balance evolution
    const returnPct = inputs.marketReturn[scenario][i] ?? 0;
    const marketAppreciation = beg * (returnPct / 100);
    const additionsToEndowment = inputs.additionsToEndowment[i] ?? 0;
    const endingEndowment =
      beg + marketAppreciation - endowmentDraw + additionsToEndowment;

    // Diagnostic rates
    const policyRate = rollingAvg > 0 ? endowmentDraw / rollingAvg : 0;
    const actualRate = beg > 0 ? endowmentDraw / beg : 0;

    out.push({
      fiscalYear: fy,
      beginningEndowment: beg,
      operatingRevenue,
      endowmentDraw,
      totalRevenue,
      awardCosts,
      opExpenses,
      totalExpenses,
      operatingNetIncome,
      rollingAverageBalance: rollingAvg,
      marketAppreciation,
      additionsToEndowment,
      endingEndowment,
      policyRate,
      actualRate,
      // Back-compat aliases
      fundraising: operatingRevenue,
      marketReturn: marketAppreciation,
      totalIncome: totalRevenue,
      totalPL: operatingNetIncome,
      spendRate: policyRate,
    });

    balanceHistory.push(endingEndowment);
    beg = endingEndowment;
  }

  return { scenario, years: out };
}

/** Run all three scenarios. */
export function projectAllScenarios(inputs: FinancialInputs): ScenarioProjection[] {
  return (['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) =>
    projectScenario(inputs, s)
  );
}

/**
 * Compute the 5-year rolling average comparator for budget reconciliation.
 * Returns the per-year 5-yr rolling avg of prior ending balances and the rate
 * that the actual draw implies against that denominator. **Display only** —
 * the live model uses 3-yr for the policy-rate diagnostic.
 *
 * Returned shape: { fiscalYear, rollingAvg5yr, impliedRate5yr } where
 * impliedRate5yr = actual endowmentDraw / 5-yr rolling avg (budget's convention).
 */
export function comparatorFiveYearRoll(
  inputs: FinancialInputs,
  projection: YearMetrics[]
): { fiscalYear: number; rollingAvg5yr: number; impliedRate5yr: number }[] {
  const history: number[] = [...inputs.priorYearBalances];
  // We also need FY22/FY23 endings to compute the 5-yr seed for FY27.
  // Pull from HISTORICAL_ENDOWMENT for the years not already in priorYearBalances.
  const earlierHistory = HISTORICAL_ENDOWMENT.filter(
    (h) => h.fiscalYear < PROJECTION_START_FY - inputs.priorYearBalances.length
  )
    .slice(-2) // FY22/FY23
    .map((h) => h.endingEndowment);
  const fullHistory: number[] = [...earlierHistory, ...history];

  return projection.map((y) => {
    const rollingAvg5yr = rollingAverage(fullHistory, COMPARATOR_WINDOW_YEARS);
    const impliedRate5yr = rollingAvg5yr > 0 ? y.endowmentDraw / rollingAvg5yr : 0;
    fullHistory.push(y.endingEndowment);
    return {
      fiscalYear: y.fiscalYear,
      rollingAvg5yr,
      impliedRate5yr,
    };
  });
}

// --- Philanthropic decomposition helpers ---

export function philanthropicTotal(p: PhilanthropicYear): number {
  return p.committed + p.likely + p.gap;
}

/**
 * For each projection year, compare the operating-revenue target to the philanthropic
 * decomposition. If they differ, the UI should surface the variance.
 */
export interface PhilanthropicReconciliation {
  fiscalYear: number;
  target: number;
  committed: number;
  likely: number;
  gap: number;
  total: number;
  variance: number; // total - target. Zero means in sync.
  pctCommitted: number; // committed / target
  pctSecured: number; // (committed + likely) / target
}

export function reconcilePhilanthropic(
  inputs: FinancialInputs
): PhilanthropicReconciliation[] {
  const years = fiscalYears();
  return years.map((fy, i) => {
    const target = inputs.fundraising[i] ?? 0;
    const p = inputs.philanthropic[i] ?? { committed: 0, likely: 0, gap: 0 };
    const total = philanthropicTotal(p);
    return {
      fiscalYear: fy,
      target,
      committed: p.committed,
      likely: p.likely,
      gap: p.gap,
      total,
      variance: total - target,
      pctCommitted: target > 0 ? p.committed / target : 0,
      pctSecured: target > 0 ? (p.committed + p.likely) / target : 0,
    };
  });
}

// --- Spend-rate guardrail thresholds ---
// Semantic: thresholds apply to the policyRate (draw / 3-yr rolling avg), which is
// the NACUBO/CommonFund convention. DC CAP's FY27 baseline at 10.34% sits well above
// the standard 4.5–5% policy band — this is the budget calibration revealing the
// operational reality, not a defect.

export const SUSTAINABLE_SPEND_RATE = 0.045; // 4.5% — common endowment policy target
export const WARN_SPEND_RATE = 0.06; // 6%+ is a yellow flag
export const ALERT_SPEND_RATE = 0.08; // 8%+ is a red flag

export type SpendRateBand = 'green' | 'yellow' | 'red';

export function spendRateBand(rate: number): SpendRateBand {
  if (rate <= SUSTAINABLE_SPEND_RATE) return 'green';
  if (rate <= WARN_SPEND_RATE) return 'yellow';
  return 'red';
}

// --- NACUBO peer benchmarks ---
// Strategic context (not compliance disclosure): the NACUBO-Commonfund Study of
// Endowments reports a typical spending-rate band around P25 ~4.0% / median ~4.7% /
// P75 ~5.2%. These are shown as a peer overlay on the policy-rate trajectory so a
// board reader can see DC CAP's FY27 trough (10.34%) bending toward the P75 band by
// FY35 (~6.4%) — the trajectory tells the story the FY27 headline alone obscures.
//
// Source: NACUBO-Commonfund 2024 Study of Endowments, spending-rate distribution.
export const NACUBO_PEER_BANDS = {
  P25: 0.04,
  MEDIAN: 0.047,
  P75: 0.052,
} as const;

// --- Going-concern floor (strategic timing, not compliance disclosure) ---
// $40M endowment ending balance is the runway floor used by the prior EndowmentRunway
// tab (archived) and Monte Carlo Stress Test (retired). Retained as a Board-attention
// threshold: if any deterministic scenario crosses this floor in the first two
// projection years, surface a banner. Framing borrowed from ASU 2014-15's substantial-
// doubt 12-month window — used here as a strategic-timing heuristic, not as a
// compliance disclosure mechanism.
export const RUNWAY_FLOOR_BALANCE = 40_000_000;

/**
 * Returns the earliest projection-year index in which ANY scenario's ending balance
 * drops below `floor`, or -1 if none. Index 0 = FY27, 1 = FY28, etc.
 *
 * Used by the going-concern banner: if return value is 0 or 1 (i.e., within the
 * first two projection years), board attention is warranted.
 */
export function firstFloorCrossingYearIndex(
  projections: ScenarioProjection[],
  floor: number
): number {
  let earliest = -1;
  projections.forEach((s) => {
    s.years.forEach((y, idx) => {
      if (y.endingEndowment < floor && (earliest === -1 || idx < earliest)) {
        earliest = idx;
      }
    });
  });
  return earliest;
}

/**
 * Returns the names of scenarios that cross below `floor` at projection year `idx`
 * (or any earlier year). Used to caption the going-concern banner.
 */
export function scenariosCrossingFloor(
  projections: ScenarioProjection[],
  floor: number,
  withinIdx: number
): ScenarioName[] {
  const out: ScenarioName[] = [];
  projections.forEach((s) => {
    const crosses = s.years
      .slice(0, withinIdx + 1)
      .some((y) => y.endingEndowment < floor);
    if (crosses) out.push(s.scenario);
  });
  return out;
}

