// --- Dev Office aspirational operating-revenue preset ---
//
// Updated 2026-05-16 (rev. 2) per Preston: match Finance's Budget Preview
// through FY29 (where its outyear panel ends), then step to $5.0M flat from
// FY30 onward. Earlier revision undershot Finance — corrected here so the
// aspirational case never falls below the Board-approved budget.
//
// Budget Preview FY28/FY29 operating revenue (Foundation + Corp + Indiv +
// Events + Contributed Services + Releases from AOR):
//   FY28 = $1.45M + $1.0M + $400K + $650K + $285K + $575K = $4,360,000
//   FY29 = $1.6M + $1.1M + $550K + $750K + $285K + $350K = $4,635,000
//
// Aspirational = AOR-bookable; P&L recognition can differ by ±$0.5M–$1M.
export const DEV_OFFICE_FY28_OPERATING_REVENUE = 4_360_000;
export const DEV_OFFICE_FY29_OPERATING_REVENUE = 4_635_000;
export const DEV_OFFICE_FY30_PLUS_STEADY_STATE = 5_000_000;

export const DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE: number[] = (() => {
  const arr: number[] = new Array(PROJECTION_LENGTH);
  arr[0] = FY27_OPERATING_REVENUE;           // FY27 — Finance baseline ($4.70M)
  arr[1] = DEV_OFFICE_FY28_OPERATING_REVENUE; // FY28 — match Finance ($4.36M)
  arr[2] = DEV_OFFICE_FY29_OPERATING_REVENUE; // FY29 — match Finance ($4.64M)
  for (let i = 3; i < PROJECTION_LENGTH; i++) {
    arr[i] = DEV_OFFICE_FY30_PLUS_STEADY_STATE; // FY30+ — $5.0M flat
  }
  return arr;
})();

export function isDevOfficeAspirationActive(operatingRevenue: number[]): boolean {
  if (operatingRevenue.length !== DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE.length) {
    return false;
  }
  return operatingRevenue.every(
    (v, i) => v === DEV_OFFICE_ASPIRATIONAL_OPERATING_REVENUE[i]
  );
}

// --- Formatting helpers ---

export function formatDollars(n: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(n);
}

export function formatMillions(n: number, fractionDigits = 1): string {
  const m = n / 1_000_000;
  const sign = m < 0 ? '-' : '';
  return `${sign}$${Math.abs(m).toFixed(fractionDigits)}M`;
}

export function formatPercent(n: number, fractionDigits = 1): string {
  return `${(n * 100).toFixed(fractionDigits)}%`;
}
