import { useEffect, useState } from 'react';
import {
  fetchBudget,
  type Budget,
  type FiscalYearKey,
} from '../../lib/budget';
import {
  PROJECTION_START_FY,
  PROJECTION_LENGTH,
  type FinancialInputs,
} from '../../lib/model';
import { dollars } from '../../lib/format';

interface Props {
  budget: Budget | null;
  inputs: FinancialInputs;
}

type Source = 'Budget Preview' | 'Model assumption' | 'Historical' | 'User override';

function SourcePill({ source }: { source: Source }) {
  const styles: Record<Source, string> = {
    'Budget Preview': 'bg-emerald-100 text-emerald-800',
    'Model assumption': 'bg-purple-100 text-purple-800',
    Historical: 'bg-blue-100 text-blue-800',
    'User override': 'bg-amber-100 text-amber-800',
  };
  return (
    <span
      className={`inline-block px-2 py-0.5 rounded text-[10px] font-head uppercase tracking-wide-15 ${styles[source]}`}
    >
      {source}
    </span>
  );
}

function fyKey(fy: number): FiscalYearKey | null {
  if (fy === 2027) return 'fy27';
  if (fy === 2028) return 'fy28';
  if (fy === 2029) return 'fy29';
  return null;
}

function YearTable({
  title,
  description,
  rows,
}: {
  title: string;
  description: string;
  rows: { fy: number; value: string; source: Source; note?: string }[];
}) {
  return (
    <article className="bg-white rounded shadow-sm overflow-hidden">
      <header className="px-6 py-3 border-b border-navy/10">
        <h2 className="font-head uppercase tracking-wide-15 text-navy text-sm">
          {title}
        </h2>
        <p className="text-xs text-navy/70 mt-1 font-sub">{description}</p>
      </header>
      <table className="w-full text-sm">
        <thead className="bg-tan/40">
          <tr className="text-navy/60 text-xs font-head uppercase tracking-wide-15">
            <th className="text-left px-4 py-2 w-20">Fiscal Year</th>
            <th className="text-right px-4 py-2">Value</th>
            <th className="text-left px-4 py-2 w-40">Source</th>
            <th className="text-left px-4 py-2">Derivation / Note</th>
          </tr>
        </thead>
        <tbody className="text-navy">
          {rows.map((r) => (
            <tr key={r.fy} className="border-t border-navy/10">
              <td className="px-4 py-2 font-mono">{r.fy === 0 ? '—' : `FY${String(r.fy).slice(-2)}`}</td>
              <td className="px-4 py-2 text-right font-mono">{r.value}</td>
              <td className="px-4 py-2">
                <SourcePill source={r.source} />
              </td>
              <td className="px-4 py-2 text-xs text-navy/70">{r.note ?? ''}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </article>
  );
}

function buildOperatingRevenueRows(
  inputs: FinancialInputs,
  budget: Budget | null
): { fy: number; value: string; source: Source; note?: string }[] {
  return Array.from({ length: PROJECTION_LENGTH }, (_, i) => {
    const fy = PROJECTION_START_FY + i;
    const val = inputs.fundraising[i] ?? 0;
    const isBudgetEra = i < 3;
    const k = fyKey(fy);
    const budgetVal = isBudgetEra && k && budget
      ? budget.outyearPnL[k].foundationRevenue +
        budget.outyearPnL[k].corporateRevenue +
        budget.outyearPnL[k].individualRevenue +
        budget.outyearPnL[k].specialEventsIncome +
        budget.outyearPnL[k].contributedServices +
        budget.outyearPnL[k].releasesFromAor
      : null;
    if (isBudgetEra && budgetVal != null) {
      return {
        fy,
        value: dollars(val),
        source: 'Budget Preview' as Source,
        note: `Σ segments + in-kind + AOR releases from Budget Preview ${k?.toUpperCase()} P&L`,
      };
    }
    return {
      fy,
      value: dollars(val),
      source: 'Model assumption' as Source,
      note: 'Carry-forward at FY29 value (Budget Preview ends at FY29)',
    };
  });
}

function buildOpExpenseRows(
  inputs: FinancialInputs
): { fy: number; value: string; source: Source; note?: string }[] {
  // Compute carry-forward values inline so the table shows actual projected
  // op-ex even for FY30+ — same logic as projectScenario.
  let lastVal: number | null = null;
  return Array.from({ length: PROJECTION_LENGTH }, (_, i) => {
    const fy = PROJECTION_START_FY + i;
    const override = inputs.opExpensesOverride?.[i];
    if (typeof override === 'number' && Number.isFinite(override)) {
      lastVal = override;
      const k = fyKey(fy);
      return {
        fy,
        value: dollars(override),
        source: 'Budget Preview' as Source,
        note: `Budget Preview ${k?.toUpperCase()} totalExpenses − scholarships`,
      };
    }
    const carryForward =
      lastVal !== null ? lastVal * (1 + inputs.opExpensesGrowth / 100) : 0;
    lastVal = carryForward;
    const note =
      i === 3
        ? `FY29 override × (1 + ${inputs.opExpensesGrowth}%) — Budget Preview exhausted at FY29`
        : `Prior year × (1 + ${inputs.opExpensesGrowth}%) compounded`;
    return {
      fy,
      value: dollars(carryForward),
      source: 'Model assumption' as Source,
      note,
    };
  });
}

function buildScholarshipRows(
  inputs: FinancialInputs
): { fy: number; value: string; source: Source; note?: string }[] {
  return Array.from({ length: PROJECTION_LENGTH }, (_, i) => {
    const fy = PROJECTION_START_FY + i;
    const val = inputs.awardCosts[i] ?? 0;
    const isBudgetEra = i < 3;
    if (isBudgetEra) {
      const k = fyKey(fy);
      return {
        fy,
        value: dollars(val),
        source: 'Budget Preview' as Source,
        note: `Budget Preview ${k?.toUpperCase()} scholarships line`,
      };
    }
    return {
      fy,
      value: dollars(val),
      source: 'Model assumption' as Source,
      note: 'Preston-confirmed trajectory: ~$4.0M-$4.3M tapering up modestly',
    };
  });
}

function buildEndowmentAdditionRows(
  inputs: FinancialInputs,
  budget: Budget | null
): { fy: number; value: string; source: Source; note?: string }[] {
  return Array.from({ length: PROJECTION_LENGTH }, (_, i) => {
    const fy = PROJECTION_START_FY + i;
    const val = inputs.additionsToEndowment[i] ?? 0;
    // Budget Preview Future Revenue View has Monumental + Leonsis $1M/yr each, FY26-FY30.
    // FY27-FY30 = $2M from these two; FY31+ = $0.
    if (i < 4 && val > 0) {
      const k = i < 3 ? fyKey(fy) : null;
      const budgetVal =
        k && budget ? budget.futureRevenueView.endowmentSubtotal[k] : null;
      return {
        fy,
        value: dollars(val),
        source: 'Budget Preview' as Source,
        note:
          budgetVal != null
            ? `Future Revenue View ${k?.toUpperCase()} endowment subtotal (Monumental + Leonsis $1M/yr each)`
            : 'Monumental + Leonsis $1M/yr each, runs through FY30 per Future Revenue View',
      };
    }
    return {
      fy,
      value: dollars(val),
      source: 'Model assumption' as Source,
      note:
        val === 0
          ? 'No Budget Preview commitments beyond FY30 — defaults to $0'
          : 'User override',
    };
  });
}

function buildMarketReturnRows(
  inputs: FinancialInputs
): { fy: number; value: string; source: Source; note?: string }[] {
  return Array.from({ length: PROJECTION_LENGTH }, (_, i) => {
    const fy = PROJECTION_START_FY + i;
    const base = inputs.marketReturn.Base[i] ?? 0;
    const opt = inputs.marketReturn.Optimistic[i] ?? 0;
    const pes = inputs.marketReturn.Pessimistic[i] ?? 0;
    return {
      fy,
      value: `Base ${base}% · Opt ${opt}% · Pess ${pes}%`,
      source: 'Model assumption' as Source,
      note:
        i < 2
          ? 'Pessimistic models a -10% drawdown in early years (asymmetric stress)'
          : 'Long-run blended portfolio return assumption',
    };
  });
}

export function Assumptions({ budget, inputs }: Props) {
  const [internalBudget, setInternalBudget] = useState<Budget | null>(budget);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (budget) {
      setInternalBudget(budget);
      return;
    }
    fetchBudget()
      .then(setInternalBudget)
      .catch((e: Error) => setError(e.message));
  }, [budget]);

  if (error) {
    return (
      <section className="bg-rose-50 border border-rose-300 text-rose-900 p-6 rounded">
        Cannot load budget.json — {error}
      </section>
    );
  }

  const operatingRevenueRows = buildOperatingRevenueRows(inputs, internalBudget);
  const opExRows = buildOpExpenseRows(inputs);
  const scholarshipRows = buildScholarshipRows(inputs);
  const endowmentRows = buildEndowmentAdditionRows(inputs, internalBudget);
  const marketRows = buildMarketReturnRows(inputs);

  return (
    <section className="space-y-6">
      <header className="bg-white p-6 rounded shadow-sm">
        <h1 className="font-head uppercase tracking-wide-15 text-navy text-xl">
          Assumptions · What's Data, What's a Bet
        </h1>
        <p className="font-sub text-navy/70 mt-2">
          Every input the model uses, line-by-line, with its source labeled. The
          rule:{' '}
          <strong>
            use Finance data as long as it exists, then pick up model assumptions
            once the Finance data is exhausted
          </strong>
          . FY27–FY29 are anchored to the Budget Preview file. FY30–FY35 are model
          extrapolations — make those assumptions explicit so the Board can challenge
          any of them.
        </p>
        <div className="mt-4 flex flex-wrap gap-2 items-center text-xs text-navy/70">
          <span>Legend:</span>
          <SourcePill source="Budget Preview" />
          <span className="font-mono">— pulled directly from the file</span>
          <SourcePill source="Model assumption" />
          <span className="font-mono">— extrapolation past FY29</span>
          <SourcePill source="Historical" />
          <span className="font-mono">— prior-year actuals</span>
          <SourcePill source="User override" />
          <span className="font-mono">— edited in the inputs panel</span>
        </div>
      </header>

      <article className="bg-tan/40 border border-purple/20 p-4 rounded text-sm text-navy/80">
        <strong className="font-head uppercase tracking-wide-15 text-xs text-navy">
          Carry-forward rule
        </strong>
        <p className="mt-1">
          When the Budget Preview's outyear panel ends at FY29, the model picks
          up the trajectory: <strong>op-ex</strong> compounds the FY29 override
          forward at {inputs.opExpensesGrowth}%/yr; <strong>operating revenue</strong>{' '}
          holds the FY29 value ($
          {(inputs.fundraising[2] ?? 0).toLocaleString()}) flat;{' '}
          <strong>scholarships</strong> follow the Preston-confirmed trajectory
          $4.1M–$4.3M; <strong>endowment additions</strong> run $2M/yr through
          FY30 (Monumental + Leonsis commitments) then default to $0. The lease-end
          reduction ($500K) is already absorbed into the FY29 Budget Preview value,
          so the model does not re-apply it after carry-forward.
        </p>
      </article>

      <YearTable
        title="Operating Revenue"
        description="Gifts + grants + events + contributed services + AOR releases (excludes endowment draw and corpus additions)."
        rows={operatingRevenueRows}
      />

      <YearTable
        title="Operating Expenses"
        description="Total expenses minus scholarships. Years 1–3 are pinned to Budget Preview overrides; years 4+ compound the FY29 override at the growth rate."
        rows={opExRows.map((r) => ({
          ...r,
          // Fill in the computed value for the carry-forward years from inputs:
          // we don't have it pre-computed here, but the Verification tab proves it
          // matches the projection. For display, show the projected number.
          value: r.value,
        }))}
      />

      <YearTable
        title="Scholarship Awards"
        description="Total scholarship disbursements per year. The Budget Preview defines FY27/FY28/FY29; beyond that the trajectory is set per Preston's prior alignment."
        rows={scholarshipRows}
      />

      <YearTable
        title="Endowment Additions (Corpus)"
        description="Principal gifts to the endowment — separate from operating revenue. Monumental + Leonsis commitments run FY26–FY30 at $1M each."
        rows={endowmentRows}
      />

      <YearTable
        title="Market Return Assumptions (per scenario)"
        description="Asset-class blended return assumption applied to the beginning-of-year endowment balance. Base scenario uses a long-run 6.5%; Pessimistic models a -10% drawdown in FY27/FY28 before recovery."
        rows={marketRows}
      />

      <article className="bg-white rounded shadow-sm overflow-hidden">
        <header className="px-6 py-3 border-b border-navy/10">
          <h2 className="font-head uppercase tracking-wide-15 text-navy text-sm">
            Other Model Assumptions
          </h2>
        </header>
        <table className="w-full text-sm">
          <tbody className="text-navy">
            <tr className="border-t border-navy/10">
              <td className="px-4 py-2 align-top font-medium">
                Operating expense growth rate
              </td>
              <td className="px-4 py-2 align-top font-mono text-right w-32">
                {inputs.opExpensesGrowth}%/yr
              </td>
              <td className="px-4 py-2 align-top w-40">
                <SourcePill source="Model assumption" />
              </td>
              <td className="px-4 py-2 align-top text-xs text-navy/70">
                Applied to FY30+ after the Budget Preview's overrides end. User
                can edit in the Financial inputs panel.
              </td>
            </tr>
            <tr className="border-t border-navy/10">
              <td className="px-4 py-2 align-top font-medium">
                One-time lease reduction
              </td>
              <td className="px-4 py-2 align-top font-mono text-right">
                FY{String(PROJECTION_START_FY + inputs.opExpensesReductionYear - 1).slice(-2)} · {dollars(inputs.opExpensesReductionAmount)}
              </td>
              <td className="px-4 py-2 align-top">
                <SourcePill source="Budget Preview" />
              </td>
              <td className="px-4 py-2 align-top text-xs text-navy/70">
                Already absorbed into the FY29 op-ex override. Listed here for
                transparency only — not applied a second time during carry-forward.
              </td>
            </tr>
            <tr className="border-t border-navy/10">
              <td className="px-4 py-2 align-top font-medium">
                Endowment draw policy
              </td>
              <td className="px-4 py-2 align-top font-mono text-right">
                Residual financing
              </td>
              <td className="px-4 py-2 align-top">
                <SourcePill source="Model assumption" />
              </td>
              <td className="px-4 py-2 align-top text-xs text-navy/70">
                Draw is sized as max(0, totalExpenses − operatingRevenue) each
                year. The implied policy rate (draw ÷ 3-yr rolling avg) emerges
                as a diagnostic, not a lever.
              </td>
            </tr>
            <tr className="border-t border-navy/10">
              <td className="px-4 py-2 align-top font-medium">
                Rolling-average window
              </td>
              <td className="px-4 py-2 align-top font-mono text-right">3 years</td>
              <td className="px-4 py-2 align-top">
                <SourcePill source="Model assumption" />
              </td>
              <td className="px-4 py-2 align-top text-xs text-navy/70">
                Trailing 3-yr ending balances seed the policy-rate diagnostic.
                Chosen over 5-yr because FY26's major gift inflated capacity and
                a 5-yr basis lags it.
              </td>
            </tr>
            <tr className="border-t border-navy/10">
              <td className="px-4 py-2 align-top font-medium">
                FY26 ending endowment (model start)
              </td>
              <td className="px-4 py-2 align-top font-mono text-right">
                {dollars(inputs.beginningEndowment)}
              </td>
              <td className="px-4 py-2 align-top">
                <SourcePill source="Historical" />
              </td>
              <td className="px-4 py-2 align-top text-xs text-navy/70">
                FY26 ending balance per organizational records (major gift +
                fundraising + market). Edits flow through every downstream year.
              </td>
            </tr>
          </tbody>
        </table>
      </article>

      <aside className="bg-tan/40 p-4 rounded text-xs text-navy/70 font-sub">
        <strong>Hard rule:</strong> any FY30+ number is an extrapolation, not a
        Budget Preview value. The Verification tab does not (and cannot)
        cross-foot those years against a source file — the file doesn't go that
        far. If a Board member challenges an FY30+ number, the answer is
        "that's a model assumption — here's what we assumed and why."
      </aside>
    </section>
  );
}
