// budget.ts — schema, loader, and accessors for budget.json.
// Source of truth: 'DCCAP 2027-00 Budget DRAFT Preview.xlsx' (the finance + dev
// merged budget). Generated by scripts/parse_budget.py with a verification gate.
//
// Naming convention:
//   - Camel-case keys mirror the parser output exactly (do not rename here).
//   - "lineItems" are the rows of a budget P&L (foundationRevenue, payroll, etc.).
//   - "departments" are the four columns of the Departments Summary
//     (operations, fundraisingDevelopment, researchInnovation, studentSuccess).
//   - "programs" are the nine cost centers from the Roll up by Program tab.
//
// View: without-GEAR-UP only. The parser strips the GEAR UP column.

export type DepartmentKey =
  | 'operations'
  | 'fundraisingDevelopment'
  | 'researchInnovation'
  | 'studentSuccess'
  | 'total';

export type ProgramKey =
  | 'operations'
  | 'fundraisingGeneral'
  | 'gradEvent'
  | 'rAndIGeneral'
  | 'kpmgAI'
  | 'up'
  | 'gearUp'
  | 'legacyPrograms'
  | 'ward7And8'
  | 'total';

export type LineKey =
  | 'foundationRevenue'
  | 'corporateRevenue'
  | 'individualRevenue'
  | 'governmentGrantIncome'
  | 'specialEventsIncome'
  | 'contributedServices'
  | 'releasesFromAor'
  | 'endowmentDraw'
  | 'totalRevenue'
  | 'payroll'
  | 'professionalFees'
  | 'programExpenses'
  | 'scholarships'
  | 'travelEvents'
  | 'rentOccupancy'
  | 'informationTechnology'
  | 'generalAdministrative'
  | 'totalExpenses'
  | 'netIncome';

export type FiscalYearKey = 'fy27' | 'fy28' | 'fy29';

export type FutureYearKey =
  | 'fy26'
  | 'fy27'
  | 'fy28'
  | 'fy29'
  | 'fy30'
  | 'future'
  | 'total';

export type SegmentKey = 'foundation' | 'corporate' | 'individual' | 'events';

export interface BudgetMeta {
  sourceFile: string;
  sourceUrl: string;
  fileLastModified: string; // ISO 8601
  syncedAt: string;
  schemaVersion: 1;
  view: 'without-GEAR-UP';
  leaseEndsAnnotation: string;
  additionsToEndowmentNote: string;
  verified: boolean;
  verificationNote: string;
}

export interface DepartmentsBlock {
  lineItems: Record<LineKey, Record<DepartmentKey, number>>;
  additionsToEndowmentText: string;
  additionsToEndowment: number;
}

export type ProgramRollup = Record<LineKey, Record<ProgramKey, number>>;

export type OutyearPnL = Record<FiscalYearKey, Record<LineKey, number>>;

export interface OperationalRevenueYear {
  foundation: number;
  corporate: number;
  individual: number;
  events: number;
  total: number;
}
export type OperationalRevenue = Record<FiscalYearKey, OperationalRevenueYear>;

export interface RevenueDetailDonor {
  segment: SegmentKey;
  name: string;
  amount: number;
  isGapPlaceholder: boolean;
  _source: { sheet: string; row: number };
}

export interface RevenueDetail {
  fy27: {
    bySegment: Record<SegmentKey, number>;
    grandTotal: number;
    donors: RevenueDetailDonor[];
  };
  fy28: { bySegment: Record<SegmentKey, number> };
  fy29: { bySegment: Record<SegmentKey, number> };
}

export interface FutureRevenueRow {
  name: string;
  _source: { sheet: string; row: number };
  fy26: number;
  fy27: number;
  fy28: number;
  fy29: number;
  fy30: number;
  future: number;
  total: number;
}

export interface FutureRevenueView {
  timeBasedReleases: FutureRevenueRow[];
  programBasedReleases: FutureRevenueRow[];
  releasesSubtotal: Record<FutureYearKey, number>;
  endowmentAdditions: FutureRevenueRow[];
  /** Sum of just the three endowment lines (Yield + Monumental + Leonsis). */
  endowmentSubtotal: Record<FutureYearKey, number>;
  /** File row 28 — combined Releases + Endowment subtotal (cross-foot anchor). */
  grandSubtotal: Record<FutureYearKey, number>;
}

export interface VerificationCheck {
  name: string;
  severity: 'hard' | 'advisory';
  passed: boolean;
  detail: string;
}

export interface Verification {
  passed: boolean;
  advisories: VerificationCheck[];
  checks: VerificationCheck[];
}

export interface SourceCell {
  sheet: string;
  row: number;
  col: number;
  cellAddress: string;
}

/** Path-keyed map of every emitted value → source xlsx cell. */
export type ProvenanceMap = Record<string, SourceCell>;

export interface Budget {
  meta: BudgetMeta;
  departments: DepartmentsBlock;
  programRollup: ProgramRollup;
  outyearPnL: OutyearPnL;
  operationalRevenue: OperationalRevenue;
  revenueDetail: RevenueDetail;
  futureRevenueView: FutureRevenueView;
  verification: Verification;
  provenance: ProvenanceMap;
}

// --- Loader ---

export async function fetchBudget(): Promise<Budget> {
  const res = await fetch(`./budget.json?t=${Date.now()}`, { cache: 'no-store' });
  if (!res.ok) {
    throw new Error(`budget.json fetch failed: ${res.status} ${res.statusText}`);
  }
  return (await res.json()) as Budget;
}

// --- Derived accessors ---

/** Operating revenue for a given fiscal year — gifts + grants + events + in-kind +
 * AOR releases. Excludes endowment draw and principal additions. */
export function operatingRevenueForFY(b: Budget, fy: FiscalYearKey): number {
  const p = b.outyearPnL[fy];
  return (
    p.foundationRevenue +
    p.corporateRevenue +
    p.individualRevenue +
    p.specialEventsIncome +
    p.contributedServices +
    p.releasesFromAor
  );
}

/** Total expenses minus scholarships = "op-ex" baseline that the model grows. */
export function opExBaselineForFY(b: Budget, fy: FiscalYearKey): number {
  const p = b.outyearPnL[fy];
  return p.totalExpenses - p.scholarships;
}

/** Principal additions to endowment for a given FY, derived from Future Revenue View
 * endowment subtotal minus any one-time line (Yield Giving lands in FY26 only). */
export function endowmentAdditionsForFY(
  b: Budget,
  fy: FiscalYearKey
): number {
  // FY27/FY28/FY29 endowment subtotal sums Yield Giving + Monumental + Leonsis.
  // Yield Giving is $0 in FY27+, so subtotal is just Monumental + Leonsis ($2M/yr).
  return b.futureRevenueView.endowmentSubtotal[fy] ?? 0;
}

// --- Functional expense split (Form 990 / Charity Navigator convention) ---
//
// Mapping (DC CAP / Budget Preview departments → 990 functional categories):
//   Program services         = Student Success + Research & Innovation
//                              + scholarships (which sit only in Student Success)
//   Management & General     = Operations
//   Fundraising              = Fundraising & Development
//
// The Budget Preview's departmental P&L already maps cleanly onto this convention
// because each line-item is allocated by department. We sum non-scholarship expenses
// by department then add scholarships into Program services.

export interface FunctionalExpenseBreakdown {
  programServices: number;
  managementAndGeneral: number;
  fundraising: number;
  total: number;
  programServicesPct: number;
  managementAndGeneralPct: number;
  fundraisingPct: number;
}

const EXPENSE_LINE_KEYS: LineKey[] = [
  'payroll',
  'professionalFees',
  'programExpenses',
  'scholarships',
  'travelEvents',
  'rentOccupancy',
  'informationTechnology',
  'generalAdministrative',
];

export function functionalExpenseBreakdown(
  b: Budget
): FunctionalExpenseBreakdown {
  const li = b.departments.lineItems;
  let programServices = 0;
  let managementAndGeneral = 0;
  let fundraising = 0;
  for (const line of EXPENSE_LINE_KEYS) {
    const row = li[line];
    if (!row) continue;
    programServices += (row.studentSuccess ?? 0) + (row.researchInnovation ?? 0);
    managementAndGeneral += row.operations ?? 0;
    fundraising += row.fundraisingDevelopment ?? 0;
  }
  const total = programServices + managementAndGeneral + fundraising;
  return {
    programServices,
    managementAndGeneral,
    fundraising,
    total,
    programServicesPct: total > 0 ? programServices / total : 0,
    managementAndGeneralPct: total > 0 ? managementAndGeneral / total : 0,
    fundraisingPct: total > 0 ? fundraising / total : 0,
  };
}

