// verification.ts — runtime defense-in-depth.
//
// The parser (scripts/parse_budget.py) runs a hard gate at build time and
// refuses to write budget.json if anything fails. This module re-runs the
// same cross-foots on the *loaded* JSON in the browser, so:
//
//   1. If budget.json is hand-edited or corrupted between parser and deploy,
//      the runtime gate catches it.
//   2. If the model's DEFAULT_INPUTS drifts from budget.json (someone tweaks
//      one without the other), the alignment check fails.
//   3. The Verification tab gives Finance a single green-light view.
//
// Severities mirror the parser's:
//   'hard'     — failure breaks the contract; tool surfaces a red banner.
//   'advisory' — drift worth surfacing but doesn't invalidate the view.

import type { Budget } from './budget';
import { operatingRevenueForFY, opExBaselineForFY } from './budget';
import type { FinancialInputs } from './model';

export interface VerificationCheck {
  /** Human-readable name shown in the UI report. */
  name: string;
  /** 'hard' blocks; 'advisory' surfaces but doesn't block. */
  severity: 'hard' | 'advisory';
  /** Layer label so the UI can group checks by L1/L2/L3/L4. */
  layer: 'L2-parser' | 'L3-runtime' | 'L4-defaults';
  passed: boolean;
  /** Specific values, deltas, or paths inspected. Always populated. */
  detail: string;
}

export interface VerificationReport {
  /** True iff every hard check passed. */
  passed: boolean;
  /** Checks failing at 'hard' severity (the headline list). */
  hardFailures: VerificationCheck[];
  /** Checks failing at 'advisory' severity (surfaced but non-blocking). */
  advisories: VerificationCheck[];
  /** All checks, in display order. */
  checks: VerificationCheck[];
  /** Aggregate counts for the UI eyebrow. */
  summary: {
    total: number;
    passed: number;
    hardFailed: number;
    advisoryFailed: number;
  };
}

const APPROX = 1.0; // $1 tolerance — Excel rounding floor.

/** Adapt parser-emitted checks into our runtime shape. */
function fromParserChecks(budget: Budget): VerificationCheck[] {
  return (budget.verification?.checks ?? []).map((c) => ({
    name: c.name,
    severity: c.severity,
    layer: 'L2-parser',
    passed: c.passed,
    detail: c.detail,
  }));
}

/** Re-run the headline cross-foots against the loaded JSON. */
function runtimeChecks(budget: Budget): VerificationCheck[] {
  const out: VerificationCheck[] = [];

  // FY27/FY28/FY29 balanced budget identity (rev = exp).
  for (const fy of ['fy27', 'fy28', 'fy29'] as const) {
    const p = budget.outyearPnL[fy];
    const delta = Math.abs(p.totalRevenue - p.totalExpenses);
    out.push({
      name: `${fy.toUpperCase()} budget balanced (rev = exp) — runtime`,
      severity: 'hard',
      layer: 'L3-runtime',
      passed: delta <= APPROX,
      detail: `Rev $${p.totalRevenue.toLocaleString()} · Exp $${p.totalExpenses.toLocaleString()} · Δ $${delta.toLocaleString()}`,
    });
  }

  // Operational revenue: total = Σ segments (FY27).
  const opr = budget.operationalRevenue.fy27;
  const segSum = opr.foundation + opr.corporate + opr.individual + opr.events;
  const oprDelta = Math.abs(opr.total - segSum);
  out.push({
    name: 'FY27 operational revenue: total = Σ segments — runtime',
    severity: 'hard',
    layer: 'L3-runtime',
    passed: oprDelta <= APPROX,
    detail: `Total $${opr.total.toLocaleString()} · Σ $${segSum.toLocaleString()} · Δ $${oprDelta.toLocaleString()}`,
  });

  // Operational revenue: Revenue Detail FY27 = Departments Summary FY27.
  const li = budget.departments.lineItems;
  const deptOp =
    li.foundationRevenue.total +
    li.corporateRevenue.total +
    li.individualRevenue.total +
    li.specialEventsIncome.total;
  const detailDelta = Math.abs(opr.total - deptOp);
  out.push({
    name: 'Revenue Detail FY27 ≈ Departments Summary — runtime',
    severity: 'hard',
    layer: 'L3-runtime',
    passed: detailDelta <= APPROX,
    detail: `Rev Detail $${opr.total.toLocaleString()} · Dept Summary $${deptOp.toLocaleString()} · Δ $${detailDelta.toLocaleString()}`,
  });

  // Departments Summary: Σ depts = TOTAL for every line.
  const failingDeptLines: string[] = [];
  for (const [lineKey, deps] of Object.entries(li)) {
    const sum =
      deps.operations +
      deps.fundraisingDevelopment +
      deps.researchInnovation +
      deps.studentSuccess;
    if (Math.abs(sum - deps.total) > APPROX) {
      failingDeptLines.push(`${lineKey} (Σ $${sum.toLocaleString()} vs $${deps.total.toLocaleString()})`);
    }
  }
  out.push({
    name: 'Departments Summary: Σ depts = TOTAL for every line — runtime',
    severity: 'hard',
    layer: 'L3-runtime',
    passed: failingDeptLines.length === 0,
    detail:
      failingDeptLines.length === 0
        ? `All ${Object.keys(li).length} lines reconcile`
        : failingDeptLines.slice(0, 3).join('; '),
  });

  // Schema sanity: provenance block exists and covers a sample of paths.
  const expectedPaths = [
    'departments.lineItems.foundationRevenue.operations',
    'programRollup.payroll.up',
    'outyearPnL.fy27.totalRevenue',
    'operationalRevenue.fy27.events',
    'futureRevenueView.releasesSubtotal.fy27',
    'futureRevenueView.endowmentSubtotal.fy27',
  ];
  // provenance keys can be either an object or undefined; coerce defensively.
  const provKeys = budget.provenance ? Object.keys(budget.provenance) : [];
  const missingPaths = expectedPaths.filter((p) => !provKeys.includes(p));
  out.push({
    name: 'Provenance block covers all sample paths — runtime',
    severity: 'hard',
    layer: 'L3-runtime',
    passed: missingPaths.length === 0,
    detail:
      missingPaths.length === 0
        ? `${provKeys.length} provenance entries; all sample paths present`
        : `missing: ${missingPaths.slice(0, 3).join(', ')}`,
  });

  return out;
}

/** L4 — verify the model's hard-coded DEFAULT_INPUTS still match the
 * Budget Preview numbers. If anyone updates budget.json (re-running the
 * parser on a new xlsx) without also updating model.ts, this fails. */
function defaultsAlignment(
  budget: Budget,
  inputs: FinancialInputs
): VerificationCheck[] {
  const out: VerificationCheck[] = [];

  const expect = (
    name: string,
    actual: number,
    expected: number,
    tolerance = APPROX
  ) => {
    const delta = Math.abs(actual - expected);
    out.push({
      name,
      severity: 'hard',
      layer: 'L4-defaults',
      passed: delta <= tolerance,
      detail: `model $${actual.toLocaleString()} · budget $${expected.toLocaleString()} · Δ $${delta.toLocaleString()}`,
    });
  };

  // FY27 operating revenue (model.fundraising[0]) must equal Budget Preview FY27 op rev.
  expect(
    'DEFAULT_INPUTS.fundraising[0] = Budget Preview FY27 operating revenue',
    inputs.fundraising[0] ?? 0,
    operatingRevenueForFY(budget, 'fy27')
  );

  // FY28 and FY29 operating revenue alignment.
  expect(
    'DEFAULT_INPUTS.fundraising[1] = Budget Preview FY28 operating revenue',
    inputs.fundraising[1] ?? 0,
    operatingRevenueForFY(budget, 'fy28')
  );
  expect(
    'DEFAULT_INPUTS.fundraising[2] = Budget Preview FY29 operating revenue',
    inputs.fundraising[2] ?? 0,
    operatingRevenueForFY(budget, 'fy29')
  );

  // FY27/FY28/FY29 op-ex override must equal Budget Preview totalExpenses − scholarships.
  for (const [idx, fy] of (['fy27', 'fy28', 'fy29'] as const).entries()) {
    const override = inputs.opExpensesOverride?.[idx];
    const expected = opExBaselineForFY(budget, fy);
    if (typeof override !== 'number') {
      out.push({
        name: `DEFAULT_INPUTS.opExpensesOverride[${idx}] populated for ${fy.toUpperCase()}`,
        severity: 'hard',
        layer: 'L4-defaults',
        passed: false,
        detail: `override is ${String(override)} — Budget Preview ${fy.toUpperCase()} = $${expected.toLocaleString()}`,
      });
      continue;
    }
    expect(
      `DEFAULT_INPUTS.opExpensesOverride[${idx}] = Budget Preview ${fy.toUpperCase()} op-ex baseline`,
      override,
      expected
    );
  }

  // FY27 scholarships alignment.
  expect(
    'DEFAULT_INPUTS.awardCosts[0] = Budget Preview FY27 scholarships',
    inputs.awardCosts[0] ?? 0,
    budget.outyearPnL.fy27.scholarships
  );
  expect(
    'DEFAULT_INPUTS.awardCosts[1] = Budget Preview FY28 scholarships',
    inputs.awardCosts[1] ?? 0,
    budget.outyearPnL.fy28.scholarships
  );
  expect(
    'DEFAULT_INPUTS.awardCosts[2] = Budget Preview FY29 scholarships',
    inputs.awardCosts[2] ?? 0,
    budget.outyearPnL.fy29.scholarships
  );

  // FY27 endowment additions alignment.
  // Budget Preview Future Revenue View endowment subtotal is the source.
  expect(
    'DEFAULT_INPUTS.additionsToEndowment[0] = Budget Preview FY27 endowment additions',
    inputs.additionsToEndowment[0] ?? 0,
    budget.futureRevenueView.endowmentSubtotal.fy27
  );

  return out;
}

export function runRuntimeVerification(
  budget: Budget | null,
  inputs?: FinancialInputs
): VerificationReport {
  if (!budget) {
    return {
      passed: false,
      hardFailures: [],
      advisories: [],
      checks: [],
      summary: { total: 0, passed: 0, hardFailed: 0, advisoryFailed: 0 },
    };
  }

  const parser = fromParserChecks(budget);
  const runtime = runtimeChecks(budget);
  const defaults = inputs ? defaultsAlignment(budget, inputs) : [];
  const checks = [...parser, ...runtime, ...defaults];

  const hardFailures = checks.filter((c) => c.severity === 'hard' && !c.passed);
  const advisories = checks.filter((c) => c.severity === 'advisory' && !c.passed);

  return {
    passed: hardFailures.length === 0,
    hardFailures,
    advisories,
    checks,
    summary: {
      total: checks.length,
      passed: checks.filter((c) => c.passed).length,
      hardFailed: hardFailures.length,
      advisoryFailed: advisories.length,
    },
  };
}

// --- Provenance lookup ---

export interface SourceProvenance {
  sheet: string;
  row: number;
  col: number;
  cellAddress: string;
}

export function provenanceFor(
  budget: Budget | null,
  path: string
): SourceProvenance | null {
  if (!budget?.provenance) return null;
  return (budget.provenance as Record<string, SourceProvenance>)[path] ?? null;
}
